// NODO 2 (Code): normalizador y Nº de orden desde el nombre
return items.map(item => {
  const j = item.json;
  const name = (j.name || j.title || "").trim();

  // 1) Nº de orden desde nombre (8–12 dígitos antes de _BL o .pdf)
  const nameNum =
    name.match(/(\d{8,12})(?=_?BL\b|_?bl\b|\.pdf$)/)?.[1] ||
    name.match(/(\d{8,12})/)?.[1] || null;

  return {
    json: {
      fileId: j.id || j.fileId,
      name,
      createdTime: j.createdTime || j.modifiedTime,
      webViewLink: j.webViewLink || j.alternateLink,
      orden_from_name: nameNum, // <-- Nº de orden detectado del nombre
      tipo: "BL_draft",
      estado: "pendiente"
    }
  };
});

// NODO 3 – Detector mínimo (orden + naviera, con booking para LOG-IN)
// Entradas por item: json.name (ej. "117779698_BL.pdf"), json.text (texto del PDF)
// Salidas: json.order_number, json.order_match, json.booking_no, json.carrier_code, json.carrier_name, json.carrier_evidence

function norm(s){ return (s||"").replace(/\r/g," ").replace(/[ \t]+/g," ").trim(); }

// 1) Nº de orden — SIEMPRE desde el nombre del archivo (8–12 dígitos)
function orderFromName(name){
  const m = (name||"").match(/(\d{8,12})(?=[_.-]?BL\b|\.pdf$)|(\d{8,12})/i);
  return m ? (m[1]||m[2]) : null;
}

// 1.1) Validar si el nº de orden aparece en el PDF (prioriza ventana cerca de "Export References"; filtra CUIT/CNPJ)
function orderAppearsInText(txt, order){
  if (!order) return null;
  const t = norm(txt);
  const reNum = new RegExp(`\\b${order}\\b`);
  // Ventanas cerca de "Export References"
  let windows = [];
  for (const m of t.matchAll(/(EXPORT\s*REFERENCES?)/gi)) {
    windows.push(t.slice(m.index, m.index + 260));
  }
  if (windows.length === 0) windows.push(t);
  for (const win of windows) {
    if (reNum.test(win) && !/(CUIT|CNPJ|TAX\s*ID|RUC)/i.test(win)) return true;
  }
  // Global fallback (con filtro fiscal alrededor)
  const idx = t.search(reNum);
  if (idx >= 0) {
    const around = t.slice(Math.max(0, idx-20), idx+String(order).length+20);
    if (!/(CUIT|CNPJ|TAX\s*ID|RUC)/i.test(around)) return true;
  }
  return false;
}

// 2) Booking (para detectar LOG-IN por prefijo LA/LM)
function readBookingLine(txt){
  const T = (txt||"").replace(/\r/g,"");
  const m = T.match(/BOOKING\s*NO\.?:?\s*([^\n]+)/i);
  return m ? m[1].trim() : null;
}
function bookingToken(bookingLine){
  if (!bookingLine) return null;
  const token = (bookingLine.match(/[A-Z]{2}\d{4,}/i)||[])[0] || null;
  return token ? token.toUpperCase() : null;
}

// 3) Carrier (naviera) — sin usar “Sea Waybill” como indicador
function stripVesselVoyageBlocks(t){
  // Evita falsos positivos por nombres de buque (p.ej. "MERCOSUL SUAPE")
  let out = t;
  out = out.replace(/VESSEL(?:\s*NAME|\(s\))?\s*[:\s].{0,140}/ig, " ");
  out = out.replace(/VOYAGE\s*[:\s].{0,80}/ig, " ");
  return out;
}
function carrierDetect(txt){
  const t = norm(txt);
  const bookingLine = readBookingLine(t);
  const bk = bookingToken(bookingLine);

  // Regla PRIORITARIA: si el booking empieza con LA o LM => LOG-IN
  if (bk && /^L[AM]\d{4,}$/.test(bk)) {
    return { code: "LOG-IN", name: "Log-In", evidence: `booking_prefix:${bk}` };
  }

  // Evidencia fuerte: "Signed by the Carrier: ..."
  const mSigned = t.match(/Signed\s+by\s+the\s+Carrier\s*[:\s-]*([^\n]+)/i);
  if (mSigned){
    const s = mSigned[1].toUpperCase();
    if (s.includes("HAPAG")) return {code:"HAPAG-LLOYD", name:"Hapag-Lloyd", evidence:`signed:${mSigned[1]}`};
    if (s.includes("SEALAND")) return {code:"SEALAND", name:"Sealand", evidence:`signed:${mSigned[1]}`};
    if (s.includes("MAERSK")) return {code:"MAERSK", name:"Maersk", evidence:`signed:${mSigned[1]}`};
    if (s.includes("MERCOSUL")) return {code:"MERCOSUL", name:"Mercosul", evidence:`signed:${mSigned[1]}`};
    if (s.includes("LOG-IN") || s.includes("LOGIN")) return {code:"LOG-IN", name:"Log-In", evidence:`signed:${mSigned[1]}`};
  }

  // Fallback por marcas, EXCLUYENDO “Sea Waybill” y EXCLUYENDO bloques de Vessel/Voyage
  const body = stripVesselVoyageBlocks(t).replace(/Sea\s*Waybill/ig, " "); // <- EXCLUIDO a pedido
  if (/Hapag[-\s]?Lloyd/i.test(body)) return {code:"HAPAG-LLOYD", name:"Hapag-Lloyd", evidence:"brand:Hapag-Lloyd"};
  if (/\bSealand\b/i.test(body))      return {code:"SEALAND",     name:"Sealand",     evidence:"brand:Sealand"};
  if (/\bMAERSK\b|\bSCAC\s+MAEU\b/i.test(body))
                                      return {code:"MAERSK",      name:"Maersk",      evidence:"brand:Maersk/MAEU"};
  if (/\bMercosul\b/i.test(body))     return {code:"MERCOSUL",    name:"Mercosul",    evidence:"brand:Mercosul"};
  if (/\bLOG[-\s]?IN\b/i.test(body))  return {code:"LOG-IN",      name:"Log-In",      evidence:"brand:Log-In"};

  return {code:null, name:null, evidence:"none"};
}

return items.map(item => {
  const j = item.json || {};
  const name = j.name || j.filename || "";
  const text = j.text || "";

  const order_number = orderFromName(name);
  const match = orderAppearsInText(text, order_number);
  const bookingLine = readBookingLine(text);
  const carrier = carrierDetect(text);

  return {
    json: {
      ...j,
      order_number,
      order_match: (match === null ? null : !!match),
      booking_no: bookingLine || null,
      carrier_code: carrier.code,
      carrier_name: carrier.name,
      carrier_evidence: carrier.evidence
    }
  };
});

