  (Array.isArray(adu?.contenedores) ? adu.contenedores : []).forEach(e => { if (e && e.container) adMap[upper(e.container)] = e; });
  (Array.isArray(ba?.equipos) ? ba.equipos : []).forEach(e => { if (e && e.container) baMap[upper(e.container)] = e; });

  // Base de filas = contenedores en BL y/o Aduana (excluir los SOLO-BA → fila fantasma).
  const keys = [...new Set([...Object.keys(blMap), ...Object.keys(adMap)])].sort();
  // Tanda C (D2): presencia por fuente — para flaggear contenedor presente en un doc y no en el otro
  // (solo si la fuente TIENE contenedores: una Aduana caída no debe gritar "no figura" en cada fila).
  const blHas = Object.keys(blMap).length > 0;
  const adHas = Object.keys(adMap).length > 0;

  // pallets BL > 0 → exigir wooden tratado en el BL.
  const palletsBL = toNum(palletsBLTotal);
  const woodenRequired = (palletsBL != null && palletsBL > 0);

  // Estado de celda: NODATA (gris) / OK (verde) / DIFF (naranja).
  const cellSt = (v, ref, diff) => (v == null ? 'NODATA' : (!diff || v === ref ? 'OK' : 'DIFF'));

  const out = [];
  for (const k of keys) {
    const eBL = blMap[k], eAD = adMap[k], eBA = baMap[k];

    const sealBL = eBL ? (eBL.seal || eBL.seal_or_precinto || '') : '';
    const sealAD = eAD ? (eAD.precinto || eAD.seal || '') : '';
    const sealDiff = (sealBL && sealAD) ? (upper(sealBL) !== upper(sealAD)) : false;

    const netBL = eBL ? toNum(eBL.nw ?? eBL.net_kg ?? eBL.nw_kg) : null;
    const netAD = eAD ? toNum(eAD.neto) : null;
    const netBA = eBA ? toNum(eBA.net_kg ?? eBA.nw) : null;
    const presentNet = [netBL, netAD, netBA].filter(v => v != null);
    const netDiff = presentNet.length >= 2 && new Set(presentNet).size > 1;
    const refNet = (netBL != null) ? netBL : netAD;

    const grBL = eBL ? toNum(eBL.gw ?? eBL.gross_kg ?? eBL.gw_kg) : null;
    const grAD = eAD ? toNum(eAD.bruto) : null;
    const grBA = eBA ? toNum(eBA.gross_kg ?? eBA.gw) : null;
    const presentGr = [grBL, grAD, grBA].filter(v => v != null);
    const grossDiff = presentGr.length >= 2 && new Set(presentGr).size > 1;
    const refGr = (grBL != null) ? grBL : grAD;

    // Measurement BL (europeo m³) → CD3 (×1000); vs Volume BA (CD3). Tolerancia = redondeo a entero.
    const measM3 = eBL ? parseNumberEU(eBL.measurement) : null;
    const measBL_cd3 = (measM3 != null) ? Math.round(measM3 * 1000) : null;
    const volRaw = eBA ? toNum(eBA.volume_cd3) : null;
    const volBA_cd3 = (volRaw != null) ? Math.round(volRaw) : null;
    const measDiff = (measBL_cd3 != null && volBA_cd3 != null) ? (measBL_cd3 !== volBA_cd3) : false;

    // Wooden BL (validación BL-only; NO se compara contra BA).
    const wm = eBL ? upper(eBL.wooden_material) : '';
    const wc = eBL ? upper(eBL.wooden_conditions) : '';
    const woodenValid = !woodenRequired || (wm === 'YES' && /TREAT/.test(wc) && /CERTIF/.test(wc));
    const woodenBL = eBL ? `${wm || '—'} / ${(eBL.wooden_conditions || '—')}` : '';

    const notas = [];
    if (sealDiff) notas.push('Seal BL≠Aduana');
    if (netDiff) notas.push('Net difiere');
    if (grossDiff) notas.push('Gross difiere');
    if (measDiff) notas.push('Measurement difiere');
    if (!woodenValid) notas.push('Wooden sin tratamiento');
    // Tanda C (D2): contenedor en un solo doc → REVISAR visible en la fila
    const missBL = !eBL && blHas, missAD = !eAD && adHas;
    if (missBL) notas.push('No figura en el BL');
    if (missAD) notas.push('No figura en Aduana');

    const estado = (sealDiff || netDiff || grossDiff || measDiff || !woodenValid || missBL || missAD) ? 'REVISAR' : 'OK';

    out.push({
      container: k,
      container_aduana: eAD ? (eAD.container || '') : '',
      // Tanda C.1 — CONTENIDO por contenedor para el mail v10 (producto · bolsas · pallets).
      // Fuente primaria: extracción del raw del BA (Inyectar Booking); fallback: Aduana
      // (producto + bultos como pallets). Multi-producto → 2+ entradas (la plantilla apila).
      contenido: (eBA && Array.isArray(eBA.contenido) && eBA.contenido.length)
        ? eBA.contenido
        : (eAD && eAD.producto ? [{ producto: eAD.producto, bolsas: null, pallets: toNum(eAD.bultos) }] : []),
      seal: { BL: sealBL, Aduana: sealAD,
              stBL: sealBL ? (sealDiff ? 'DIFF' : 'OK') : 'NODATA',
              stAD: sealAD ? (sealDiff ? 'DIFF' : 'OK') : 'NODATA' },
      net: { BL: netBL, Aduana: netAD, Booking: netBA,
             stBL: cellSt(netBL, refNet, netDiff), stAD: cellSt(netAD, refNet, netDiff), stBA: cellSt(netBA, refNet, netDiff) },
      gross: { BL: grBL, Aduana: grAD, Booking: grBA,
               stBL: cellSt(grBL, refGr, grossDiff), stAD: cellSt(grAD, refGr, grossDiff), stBA: cellSt(grBA, refGr, grossDiff) },
      // FIX1: presentación en m³ (BL ya viene en m³; BA = volume_cd3/1000). La comparación interna sigue en CD3 (measDiff).
      meas: { BL_m3: measM3, BA_m3: (volRaw != null ? volRaw / 1000 : null),
              stBL: measBL_cd3 == null ? 'NODATA' : (measDiff ? 'DIFF' : 'OK'),
              stBA: volBA_cd3 == null ? 'NODATA' : (measDiff ? 'DIFF' : 'OK') },
      wooden: { BL: woodenBL, st: eBL ? (woodenValid ? 'OK' : 'DIFF') : 'NODATA' },
      estado,
      notas: notas.join('; '),
    });
  }
  // Tanda C (D2): control de LISTA de contenedores (antes era la fila "Contenedores (lista)" del
  // cuadro principal) — ahora estado + nota del bloque Detalle por contenedor.
  const setBL2 = new Set(Object.keys(blMap)), setAD2 = new Set(Object.keys(adMap)), setBA2 = new Set(Object.keys(baMap));
  const eqSets2 = (a, b) => a.size === b.size && [...a].every((x) => b.has(x));
  const notasMeta = [];
  if (setBL2.size && setAD2.size && !eqSets2(setBL2, setAD2)) notasMeta.push('Contenedores BL ≠ Aduana (error de despacho)');
  else if (setBA2.size && !eqSets2(setBA2, setBL2.size ? setBL2 : setAD2)) notasMeta.push('BA difiere (posible error de planta); BL y Aduana coinciden');
  // Tanda C.1 — resumen para el mail v10: "N/N coinciden" + valores uniformes (si TODA la
  // flota comparte neto/bruto/vol/wooden, el detalle numérico sube a una sola línea).
  const coinciden = out.filter((r) => r.estado === 'OK').length;
  let uniforme = null;
  if (out.length) {
    const distinct = (f) => [...new Set(out.map((r) => { const v = f(r); return v == null ? '' : String(v); }))];
    const nets = distinct((r) => r.net.BL ?? r.net.Aduana);
    const grs  = distinct((r) => r.gross.BL ?? r.gross.Aduana);
    const vols = distinct((r) => r.meas.BL_m3 ?? r.meas.BA_m3);
    const wood = distinct((r) => r.wooden.BL);
    if (nets.length === 1 && nets[0] !== '' && grs.length === 1 && vols.length === 1 && wood.length === 1) {
      uniforme = { neto: out[0].net.BL ?? out[0].net.Aduana, bruto: out[0].gross.BL ?? out[0].gross.Aduana,
                   vol_m3: out[0].meas.BL_m3 ?? out[0].meas.BA_m3, wooden: out[0].wooden.BL };
    }
  }
  return { rows: out, meta: { estado: notasMeta.length ? 'REVISAR' : 'OK', notas: notasMeta },
           resumen: { total: out.length, coinciden, uniforme } };
}

/* =========================
   FACTURA (4º documento) — PUT-4: cruce por producto (grade), carteles, comentarios, guard
   Tanda B: matcheo por niveles (núcleo+sufijo), Booking como 4ª fuente, sin descartes silenciosos.
   ========================= */
// Normalización de texto de producto: mayúsculas, sin ™/®, espacios colapsados.
const normProd = (s) => String(s == null ? '' : s).toUpperCase().replace(/[™®]/g, '').replace(/\s+/g, ' ').trim();
// N1: núcleo (3-5 dígitos) + sufijo (≤2 letras), tolerando UN espacio interno: "7000 H" ≡ "7000H".
// El lookahead exige fin de token: en "35060 BAGS" el sufijo NO se come la "BA" de BAGS → "35060".
const GRADE_RX = /(\d{3,5})(?:\s?([A-Z]{1,2}))?(?![A-Z0-9])/;
// Devuelve {core, suffix, key} o null (string vacío). Sin núcleo numérico → key = nombre
// normalizado completo (antes se DESCARTABA el producto en silencio — otro drop silencioso).
const gradeParts = (s) => {
  const t = normProd(s);
  if (!t) return null;
  const m = t.match(GRADE_RX);
  if (m) return { core: m[1], suffix: m[2] || '', key: m[1] + (m[2] || '') };
  return { core: null, suffix: '', key: t };
};
const DOC_LABEL = { BL: 'BL', FC: 'Factura', Adu: 'Aduana', BA: 'Booking' };

function buildProductos(bl, fc, adu, ba, isBulk) {
  // Tanda BULK: isBulk con default false preserva la firma para cualquier caller anterior
  // (ningún caller externo pasa este argumento; solo buildComparison lo pasa explícitamente).
  isBulk = !!isBulk;
  /* ---- 1) Agrupar por key exacta (post-normalización) por documento ----
     La key nueva ya une los splits por formato/espacio ("7000 H" vs "7000H") SIN flag. */
  const groups = {};
  const ensure = (gp) => (groups[gp.key] || (groups[gp.key] = { key: gp.key, core: gp.core, suffix: gp.suffix, BL: null, FC: null, Adu: null }));
  (Array.isArray(bl && bl.products) ? bl.products : []).forEach((p) => {
    if (!p) return;   // guard de elemento null (espejo de buildCompareEquipos)
    const gp = gradeParts(p.goods || p.grade || ''); if (!gp) return;
    const e = ensure(gp);
    e.BL = e.BL || { bags: 0, net: 0, gross: 0, pallets: 0, goods: p.goods || p.grade || '' };
    e.BL.bags += toNum(p.bags) || 0; e.BL.net += toNum(p.net_kg) || 0; e.BL.gross += toNum(p.gross_kg) || 0; e.BL.pallets += toNum(p.pallets) || 0;
  });
  (Array.isArray(fc && fc.items) ? fc.items : []).forEach((it) => {
    if (!it) return;
    const gp = gradeParts(it.description || it.grade || ''); if (!gp) return;
    const e = ensure(gp);
    e.FC = e.FC || { bags: 0, net: 0, gross: 0, pallets: 0, desc: it.description || it.grade || '', embalaje: it.embalaje || '', product_code: it.product_code || '', material: it.material || '' };
    e.FC.bags += toNum(it.bags) || 0; e.FC.net += toNum(it.net_kg) || 0; e.FC.gross += toNum(it.gross_kg) || 0; e.FC.pallets += toNum(it.pallets) || 0;
  });
  (Array.isArray(adu && adu.contenedores) ? adu.contenedores : []).forEach((c) => {
    if (!c) return;
    const gp = gradeParts(c.producto || ''); if (!gp) return;
    const e = ensure(gp);
    e.Adu = e.Adu || { conts: 0, net: 0, gross: 0, bultos: 0, prod: c.producto || '' };
    e.Adu.conts += 1; e.Adu.net += toNum(c.neto) || 0; e.Adu.gross += toNum(c.bruto) || 0; e.Adu.bultos += toNum(c.bultos) || 0;
  });

  const avisos = [];
  const addAviso = (docName, text, level = 'warn') => avisos.push({ doc: docName, level, text });

  /* ---- 2) Fusión entre keys del MISMO núcleo con sufijos compatibles ----
     "6502" (Aduana omite la letra final) + "6502B" (BL/FC) → UNA fila (NUNCA "producto adicional"),
     estado SIEMPRE REVISAR (la letra define el producto; puede ser documentación errada del despachante).
     Guardias: (a) colisión intra-doc (un doc declara 2 keys del mismo núcleo) → no fusionar ese núcleo;
               (b) magnitudes: ambos lados declaran net o gross > 0 y difieren → NO fusionar
                   (protege contra planilla multi-orden con producto ajeno de mismo núcleo);
               (c) ambigüedad: compatible con 2+ clusters → fila propia, aviso.
     BA NO entra acá: es doc-level (un producto por Booking), se integra en el paso 3. */
  const SRC3 = ['BL', 'FC', 'Adu'];
  const byCore = {};
  Object.values(groups).forEach((g) => {
    const c = g.core ? g.core : ('#' + g.key);   // sin núcleo: solo match exacto (no fusiona)
    (byCore[c] = byCore[c] || []).push(g);
  });
  const repVal = (g, f) => { for (const s of SRC3) { if (g[s] && g[s][f] > 0) return g[s][f]; } return null; };
  const sufCompat = (a, b) => a.indexOf(b) === 0 || b.indexOf(a) === 0;

  const clusters = [];
  for (const core of Object.keys(byCore).sort()) {
    const members = byCore[core].sort((a, b) => (b.suffix.length - a.suffix.length) || (a.key < b.key ? -1 : 1));
    if (members.length === 1 || core.charAt(0) === '#') { members.forEach((m) => clusters.push([m])); continue; }
    const colisionDocs = SRC3.filter((s) => members.filter((m) => m[s]).length >= 2);
    if (colisionDocs.length) {
      members.forEach((m) => clusters.push([m]));
      addAviso('Productos', `Núcleo ${core} repetido dentro de ${colisionDocs.map((s) => DOC_LABEL[s]).join(', ')} (${members.map((m) => m.key).join(' / ')}) — no se cruzaron automáticamente; revisar.`);
      continue;
    }
    const built = [];
    for (const m of members) {
      const compat = built.filter((cl) => {
        const lead = cl[0];
        if (!sufCompat(lead.suffix, m.suffix)) return false;
        const nA = repVal(lead, 'net'), nB = repVal(m, 'net');
        if (nA != null && nB != null && nA !== nB) return false;
        const gA = repVal(lead, 'gross'), gB = repVal(m, 'gross');
        if (gA != null && gB != null && gA !== gB) return false;
        return true;
      });
      if (compat.length === 1) compat[0].push(m);
      else {
        if (compat.length > 1) addAviso('Productos', `Producto ${m.key}: núcleo ${core} compatible con ${compat.map((c2) => c2[0].key).join(' y ')} — no se pudo atribuir automáticamente; revisar.`);
        built.push([m]);
      }
    }
    built.forEach((cl) => clusters.push(cl));
  }

  /* ---- 2b) Keys SIN núcleo (familia sola): "LLDPE" (Aduana) vs "LLDPE 1613.11..." (BL/FC/BA).
     Si el nombre-key es substring del nombre de UN solo cluster y las magnitudes no se contradicen,
     se une a ese cluster como nombre divergente (REVISAR + cartel) — el viejo gradeKey lo DESCARTABA
     en silencio y la fila de Aduana desaparecía. Ambiguo (2+ clusters) → fila propia + aviso. */
  const partNames = (p) => SRC3.map((s) => p[s] && normProd(s === 'BL' ? p[s].goods : (s === 'FC' ? p[s].desc : p[s].prod))).filter(Boolean);
  for (let i = clusters.length - 1; i >= 0; i--) {
    const cl = clusters[i];
    if (cl.length !== 1 || cl[0].core || cl[0].key.length < 3) continue;
    const m = cl[0];
    const cands = clusters.filter((c2) => {
      if (c2 === cl || !c2[0].core) return false;
      if (!c2.some((p) => partNames(p).some((nm) => nm.indexOf(m.key) >= 0))) return false;
      const nA = repVal(c2[0], 'net'), nB = repVal(m, 'net');
      if (nA != null && nB != null && nA !== nB) return false;
      const gA = repVal(c2[0], 'gross'), gB = repVal(m, 'gross');
      if (gA != null && gB != null && gA !== gB) return false;
      return true;
    });
    if (cands.length === 1) { cands[0].push(m); clusters.splice(i, 1); }
    else if (cands.length > 1) addAviso('Productos', `Producto '${m.key}' (sin código de grado) coincide con ${cands.map((c2) => c2[0].key).join(' y ')} — no se pudo atribuir automáticamente; revisar.`);
  }

  /* ---- 3) Booking (doc-level): matchea por nombre la fila existente; informativo,
     NUNCA participa de los diffs de magnitudes. Cantidades (totales del doc) solo en mono. ---- */
  let baEntry = null;
  const baProd = (ba && ba.producto) || null;
  if (baProd && (baProd.grado || baProd.cadena)) {
    const gp = gradeParts(baProd.grado || baProd.cadena);
    if (gp) baEntry = { gp, cadena: baProd.cadena || baProd.grado || '', grado: baProd.grado || '', embalaje: baProd.embalaje || '' };
  }
  let baCluster = null, baNombreDif = false, baNombreDifCoreMatch = false;
  if (baEntry) {
    baCluster = clusters.find((cl) => cl.some((m) => m.key === baEntry.gp.key)) || null;
    if (!baCluster && baEntry.gp.core) {
      const comp = clusters.filter((cl) => cl[0].core === baEntry.gp.core && sufCompat(cl[0].suffix, baEntry.gp.suffix));
      // G3 regla del ancla: core-match path → baNombreDifCoreMatch=true (INFO si lead ≥2 docs)
      if (comp.length === 1) { baCluster = comp[0]; baNombreDif = true; baNombreDifCoreMatch = true; }
    }
    // mono sin match: el BA es doc-level → se adjunta a la única fila (comportamiento actual) pero VISIBLE.
    // G3: mono-attach → baNombreDifCoreMatch=false → nombre_difiere → REVISAR
    if (!baCluster && clusters.length === 1) { baCluster = clusters[0]; baNombreDif = true; }
  }

  /* ---- 4) Filas finales ---- */
  const expected = SRC3.filter((s) => Object.values(groups).some((g) => g[s]));
  const rows = []; let revisar = 0;
  const buildRow = (cl, baAttach, baFlag, baFlagIsCore) => {
    const lead = (cl && cl.length) ? cl[0] : null;
    const key = lead ? lead.key : baAttach.gp.key;
    const e = { BL: null, FC: null, Adu: null };
    const nombreDif = [];     // G3: REVISAR — sin core (2b) o con core pero lead con 1 doc
    const nombreDifInfo = []; // G3: info  — con core y lead confirmado ≥2 docs; o BA core-match
    // G3 regla del ancla: conteo de docs en el lead (BL/FC/Adu)
    const leadDocCount = lead ? SRC3.filter((s) => lead[s]).length : 0;
    (cl || []).forEach((m) => {
      SRC3.forEach((s) => { if (m[s] && !e[s]) { e[s] = m[s]; if (m !== lead) { (m.core && leadDocCount >= 2 ? nombreDifInfo : nombreDif).push(DOC_LABEL[s]); } } });
    });
    // G3: BA core-match (baFlagIsCore) → info si lead ≥2 docs; BA mono-attach → REVISAR
    if (baFlag) (baFlagIsCore && leadDocCount >= 2 ? nombreDifInfo : nombreDif).push(DOC_LABEL.BA);
    const BA = baAttach ? { cadena: baAttach.cadena, grado: baAttach.grado, embalaje: baAttach.embalaje, bags: null, pallets: null, net: null, gross: null } : null;
    const presentes = SRC3.filter((d) => e[d]).concat(BA ? ['BA'] : []);
    // magnitudes SOLO entre docs que las declaran (>0). Aduana NO declara bolsas → bags NODATA (D5). BA informativo.
    const netVals = [e.BL && e.BL.net, e.FC && e.FC.net, e.Adu && e.Adu.net].filter((v) => v != null && v !== 0);
    const grossVals = [e.BL && e.BL.gross, e.FC && e.FC.gross, e.Adu && e.Adu.gross].filter((v) => v != null && v !== 0);
    const bagsVals = [e.BL && e.BL.bags, e.FC && e.FC.bags].filter((v) => v != null && v !== 0);
    const netDiff = netVals.length >= 2 && new Set(netVals).size > 1;
    const grossDiff = grossVals.length >= 2 && new Set(grossVals).size > 1;
    const bagsDiff = bagsVals.length >= 2 && new Set(bagsVals).size > 1;
    const faltan = expected.filter((d) => !e[d]);   // docs CON productos parseados donde esta fila no aparece
    const diffReal = netDiff || grossDiff || bagsDiff;
    const estado = (diffReal || nombreDif.length || faltan.length) ? 'REVISAR' : 'OK';
    if (estado === 'REVISAR') revisar++;
    nombreDif.forEach((d) => {
      if (d === 'Aduana') addAviso('Aduana', `Producto ${key}: el nombre difiere en la planilla de Aduana ('${(e.Adu && e.Adu.prod) || ''}') — verificar con el despachante.`);
      else if (d === 'Booking') addAviso('Booking', `Producto ${key}: el nombre difiere en el Booking ('${(BA && BA.cadena) || ''}') — revisar.`);
      else addAviso(d, `Producto ${key}: el nombre difiere entre los documentos (${d}: '${(d === 'Factura' ? (e.FC && e.FC.desc) : (e.BL && e.BL.goods)) || ''}') — revisar.`);
    });
    // G3: avisos informativos para fusiones con core numérico (paso 2) y BA
    nombreDifInfo.forEach((d) => {
      const val = d === 'Aduana' ? (e.Adu && e.Adu.prod) : d === 'Booking' ? (BA && BA.cadena) : d === 'Factura' ? (e.FC && e.FC.desc) : (e.BL && e.BL.goods);
      addAviso(d, `Producto ${key}: nombre abreviado/variante en ${d} ('${val || ''}') — mismo grado; verificar con el despachante si corresponde.`, 'info');
    });
    if (faltan.length) addAviso('Productos', `Producto ${key}: sin contraparte en ${faltan.map((d) => DOC_LABEL[d]).join(', ')} — revisar.`);
    const nombre = (e.BL && String(e.BL.goods).trim()) || (e.FC && String(e.FC.desc).trim())
      || (BA && String(BA.cadena).trim()) || (e.Adu && String(e.Adu.prod).trim()) || key;
    const _rowBase = { grade: key, presentes, nombre, BL: e.BL, FC: e.FC, Adu: e.Adu, BA,
      nombre_difiere: nombreDif,
      diffs: { net: netDiff, gross: grossDiff, bags: bagsDiff, nombre: !!nombreDif.length, faltan },
      estado };
    if (nombreDifInfo.length) _rowBase.nombre_dif_info = nombreDifInfo;
    rows.push(_rowBase);
  };
  clusters.forEach((cl) => buildRow(cl, (baCluster === cl) ? baEntry : null, (baCluster === cl) ? baNombreDif : false, (baCluster === cl) ? baNombreDifCoreMatch : false));
  if (baEntry && !baCluster) buildRow(null, baEntry, false, false);   // np=0 (ancla la tabla) o multi sin match
  rows.sort((a, b) => (a.grade < b.grade ? -1 : a.grade > b.grade ? 1 : 0));

  // Cantidades del BA (totales doc-level) SOLO con tabla mono — en multi no son por-producto.
  if (rows.length === 1 && ba && ba.totales) {
    if (!rows[0].BA) rows[0].BA = { cadena: '', grado: '', embalaje: (baProd && baProd.embalaje) || '', bags: null, pallets: null, net: null, gross: null };
    const t = ba.totales;
    // Tanda BULK (gate D): bags se anula SOLO si es bulk o la unidad es explícitamente KG (peso).
    // unit null (regex sin match / docs pre-PUT) o cualquier otra unidad → comportamiento actual
    // intacto: un containerizado jamás pierde el desglose por una falla del regex de unidad.
    const pcUnit = t.piece_count_unit;
    rows[0].BA.bags = (isBulk || pcUnit === 'KG') ? null
      : ((t.piece_count != null) ? toNum(t.piece_count) : null);
    rows[0].BA.net = (t.net_kg != null) ? toNum(t.net_kg) : null;
    rows[0].BA.gross = (t.gross_kg != null) ? toNum(t.gross_kg) : null;
    const bpp = toNum(ba.bags_per_pallet);
    rows[0].BA.pallets = (rows[0].BA.bags != null && bpp) ? Math.round(rows[0].BA.bags / bpp) : null;
  }

  // multiproducto: por núcleos distintos del BL (no por filas: una fila huérfana no es "multi").
  const blCores = new Set();
  (Array.isArray(bl && bl.products) ? bl.products : []).forEach((p) => { if (!p) return; const gp = gradeParts(p.goods || p.grade || ''); if (gp) blCores.add(gp.core || gp.key); });
  const multiproducto = blCores.size >= 2 || (!blCores.size && rows.length >= 2);
  return { rows, revisar, count: rows.length, multiproducto, avisos };
}

function buildHeaderBadges(bl, fc, prod) {
  const _n14 = (s) => { const d = String(s == null ? '' : s).replace(/\D+/g, ''); return d.length > 14 ? d.slice(-14) : d; };
  const soldTax = _n14(fc && fc.sold_to && fc.sold_to.tax);
  const shipTax = _n14(fc && fc.ship_to && fc.ship_to.tax);
  const triangular = !!(soldTax && shipTax && soldTax !== shipTax);
  return { triangular, multiproducto: !!(prod && prod.multiproducto), sold_tax: soldTax, ship_tax: shipTax };
}

function buildProactiveComments(doc, bl, ba, fc, badges) {
  const out = [];
  const add = (docName, level, text) => out.push({ doc: docName, level, text });
  const fm = doc.factura_meta || {};
  if (fm.refacturacion) add('Factura', 'warn', `Posible refacturación: el N° interno de la FC (${fm.order_internal || '—'}) difiere del N° de orden del nombre de archivo (${fm.order_filename || '—'}). Esta FC es la que se controla; verificar permiso y datos.`);
  if (fm.duplicate) add('Factura', 'warn', `Hay ${fm.count} facturas para esta orden en FACTURAS EXPORTACION; no se auto-eligió — verificar cuál es la vigente.`);
  if (!doc.factura_extract) add('Factura', 'info', 'No se encontró factura para esta orden en FACTURAS EXPORTACION.');
  if (badges && badges.triangular) add('Factura', 'info', `Orden TRIANGULAR: Sold To (${badges.sold_tax}) ≠ Ship To (${badges.ship_tax}).`);
  const nm = (ba && ba.notify_meta) || {};
  if (nm.notify_multiple || nm.notify_differ) add('Booking', 'info', 'Booking: el notify estructurado y el de instrucciones difieren — ya marcado en la tabla; revisar a futuro.');
  return out;
}

function buildGuard(doc) {
  const out = [];
  if (!doc.login_extract) out.push({ doc: 'BL', motivo: 'BL ausente (login_extract null)' });
  if (!doc.aduana_extract) out.push({ doc: 'Aduana', motivo: 'Planilla de Aduana no unida (ausente o joinKey desalineado)' });
  if (!doc.booking_extract) out.push({ doc: 'Booking', motivo: 'Booking Advice no unido (ausente o joinKey desalineado)' });
  else {
    // Tanda A: Booking unido pero degradado/sospechoso — fallo visible, no silencioso.
    if (doc.booking_extract.error) out.push({ doc: 'Booking', motivo: 'Booking: parseo falló (429/error IA) — reintentar' });
    if (doc.booking_extract.order_mismatch) out.push({ doc: 'Booking', motivo: 'Orden: el nombre del archivo no coincide con la extraída — revisar' });
  }
  if (!doc.factura_extract) {
    if (doc.factura_meta && doc.factura_meta.found) out.push({ doc: 'Factura', motivo: 'Factura hallada pero no unida (joinKey desalineado)' });
    else out.push({ doc: 'Factura', motivo: 'Factura no encontrada en FACTURAS EXPORTACION' });
  }
  // Tanda B: parsers degradados VISIBLES — por truthiness de .error (el texto real del 429 dice
  // "too many requests", NO contiene "429" — nunca matchear el string).
  if (doc.aduana_extract && doc.aduana_extract.error) out.push({ doc: 'Aduana', motivo: 'Aduana: parseo falló (rate limit/error IA) — reintentar' });
  if (doc.factura_extract && doc.factura_extract.error) out.push({ doc: 'Factura', motivo: 'Factura: parseo falló (rate limit/error IA) — reintentar' });
  // BL: el 429 del parser LOG-IN llega TRAGADO por Inyectar metadata (login_extract sin .error,
  // products vacío con goods_block_raw presente) → detectar el patrón, sin atribuir 429.
  const _le = doc.login_extract;
  if (_le && !((Array.isArray(_le.products) ? _le.products : []).length) && /DESCRIPTION\s+GOODS/i.test(String(_le.goods_block_raw || ''))) {
    out.push({ doc: 'BL', motivo: 'BL: lista de productos vacía pese a texto presente (parser IA caído o respuesta incompleta) — reintentar' });
  }
  return out;
}

/* =========================
   Tanda C — layout BL-anchored: una entrada por casillero del formulario BL (2→17),
   BL primera columna fija + docs comparados a la derecha; bloque "Totales y controles";
   estados por comparación con colapso OR por campo (D6: contador = ítems distintos).
   Reemplaza compare_excel_pairs/compare_factura (retirados — sin consumidores, D7).
   ========================= */
const stripPortName = (s) => upper(s).replace(/\s*PORT\s*$/i, '').trim();
const eqPort = (a, b) => { const x = stripPortName(a), y = stripPortName(b); return !!(x && y) && (x === y || x.indexOf(y) >= 0 || y.indexOf(x) >= 0); };
const firstLineKey = (s) => String(s || '').split('\n')[0].toUpperCase().replace(/[^A-Z]/g, '');
// (8) POINT AND COUNTRY: el valor vive pegado al label en el raw del BL ("Argentina" 10/10) — D4.
const pointAndCountryFromText = (txt) => {
  const m = String(txt || '').match(/\(8\)\s*POINT AND COUNTRY\s*\n?\s*([^\n(]*)/i);
  return m ? m[1].trim() : '';
};
const normPE = (s) => upper(s).replace(/\s+/g, '');
const prefix4 = (s) => cleanDigits(s).slice(0, 4);
// PE work-stream: posición arancelaria full normalizada ("3901.20.29.900U" -> "39012029900U").
const normPA = (s) => upper(s).replace(/[^0-9A-Z]/g, '');
// Coerción numérica segura para montos PE/FC: ya vienen como Number desde los Inyectar (num/moneyUSD).
// Para Number se devuelve tal cual (NO se re-aplica la heurística de miles de toNum, que corrompería
// p.ej. 300.004 -> 300004). Sólo strings sueltos caen a toNum. Evita falso REVISAR en seguro/flete.
const numSafe = (x) => (typeof x === 'number' ? (Number.isFinite(x) ? x : null) : toNum(x));
// PE: ÚNICO regex prepaid (decisión #2) — el mismo del bloque de flete existente. RE_SEGURO_INC ⊂ prepaid.
const RE_FLETE_PREPAID = /^(CPT|CIF|CFR|CIP)/;
const RE_SEGURO_INC = /^(CIF|CIP)/;
// Embalaje: igualdad laxa por contención ("25 KG Bags" ⊇ "Bags").
// G2 Tanda G: Big Bag(s) / BigBag(s) ≡ Bag(s) — solo esa familia; Bulk y resto intactos.
const normEmb = (s) => { const u = upper(s); return u.replace(/\bBIG\s*BAGS?\b/g, 'BAGS').replace(/\bBIGBAGS?\b/g, 'BAGS').replace(/\bBAGS\b/g, 'BAG'); };
const eqEmb = (a, b) => { const x = normEmb(a), y = normEmb(b); return !!(x && y) && (x === y || x.indexOf(y) >= 0 || y.indexOf(x) >= 0); };

function buildComparison(doc) {
  const bl = doc.login_extract || {};
  const ba = doc.booking_extract || {};
  const adu = doc.aduana_extract || {};
  const fc = doc.factura_extract || {};
  const pe = doc.pe_extract || null;   // PE work-stream: doc Permiso de Exportación; null = ausente (decisión #1)

  // ── Tanda BULK: discriminador is_bulk ──────────────────────────────────────────────────────
  // Se computa UNA vez sobre campos ESTRUCTURADOS (goods_block_raw del BL, que está scopeado al
  // bloque de mercadería; y producto/embalaje del BA estructurado). PROHIBIDO usar doc.text,
  // up.text del BA raw, ni address_str: los BAs de órdenes BAGS normales contienen "Bulk" literal
  // en su boilerplate (secciones "Bulk and Granules Introduction" / "Bulk Port") → falso positivo
  // en TODO el corpus containerizado. Verificado: 0/40 FPs en corpus; 3/3 bulk detectados.
  const RE_BULK = /\b(BULK|BLK)\b/i;
  const isBulk = RE_BULK.test(bl.goods_block_raw || '')
    || RE_BULK.test(String((ba.producto && (ba.producto.cadena || '')) || '') + ' ' + String((ba.producto && (ba.producto.embalaje || '')) || ''));
  // ──────────────────────────────────────────────────────────────────────────────────────────────

  const counters = { OK: 0, REVISAR: 0 };
  const bump = (st) => { if (st === 'REVISAR') counters.REVISAR++; else counters.OK++; };

  /* ---- helpers del contrato ---- */
  const comp = (docName, label, valor, estado, nota, multiline) => ({
    doc: docName, label: label || docName, valor: valor == null ? '' : String(valor),
    estado: estado || 'NODATA', nota: nota || '', multiline: !!multiline,
  });
  const mkEntry = (num, titulo, tipo, blVal, comps, opts) => {
    const o = opts || {};
    const comparaciones = (comps || []).filter(Boolean);
    const subs = (o.subs || []).filter(Boolean);
    const anyRev = comparaciones.some((c) => c.estado === 'REVISAR') || subs.some((s) => s.estado === 'REVISAR');
    const estado = (tipo === 'comparacion') ? (anyRev ? 'REVISAR' : 'OK') : 'INFO';
    if (tipo === 'comparacion') bump(anyRev ? 'REVISAR' : 'OK');
    else if (tipo === 'informativo') bump('OK');   // los vacíos no cuentan: no hay control
    return { num, titulo, tipo, fmt: o.fmt || '',
      bl: { valor: blVal == null ? '' : String(blVal), multiline: !!o.multiline },
      comparaciones, subs, estado, nota: o.nota || '' };
  };

  /* ================= SECCIÓN 1 — casilleros (2)→(17) ================= */
  const campos = [];

  // (2) SHIPPER / EXPORTER ↔ Factura.exporter (1ª línea) — override migrado del render
  const blShipper = buildBlock(bl.shipper || '');
  const fcExporter = String((fc && fc.exporter) || '').trim();
  let c2 = null;
  if (fcExporter) {
    const a = firstLineKey(blShipper), b = firstLineKey(fcExporter);
    const st = (a && b) ? (a === b ? 'OK' : 'REVISAR') : 'NODATA';
    c2 = comp('Factura', 'Factura (exportador)', fcExporter, st,
      st === 'OK' ? 'Embarcador = Exportador (BL = Factura)' : (st === 'REVISAR' ? 'Shipper (BL) ≠ Exportador (Factura)' : ''), true);
  }
  campos.push(mkEntry('2', 'SHIPPER / EXPORTER', 'comparacion', blShipper, [c2], { multiline: true }));

  // (3) CONSIGNEE ↔ Booking.consignee (CNPJ) + Factura.SHIP TO (corrección John) — override migrado
  const blConsignee = buildBlock(bl.consignee || '');
  const taxBL = norm14(bl.consignee_tax || (/CNPJ\s*([\d./-]+)/i.exec(String(bl.consignee || '')) || [])[1] || '');
  const baConsigneeBlock = buildBlock(ba.consignee || {});
  const taxBA = norm14((ba && ba.consignee && ba.consignee.tax_id) || '');
  let c3ba = null;
  if (baConsigneeBlock || taxBA) {
    const st = (taxBL && taxBA) ? (taxBL === taxBA ? 'OK' : 'REVISAR') : ((taxBL || taxBA) ? 'REVISAR' : 'NODATA');
    c3ba = comp('Booking', 'Booking (consignee)', baConsigneeBlock, st,
      st === 'REVISAR' ? 'CNPJ del consignee difiere o falta en un documento' : '', true);
  }
  const fcShipName = (fc && fc.ship_to && fc.ship_to.name) || '';
  const fcShipTax = norm14((fc && fc.ship_to && fc.ship_to.tax) || '');
  let c3fc = null;
  if (fcShipName || fcShipTax) {
    const ref = taxBL || taxBA;
    const st = (ref && fcShipTax) ? (ref === fcShipTax ? 'OK' : 'REVISAR') : 'NODATA';
    c3fc = comp('Factura', 'Factura (Ship To)', `${fcShipName}${fcShipTax ? '\nCNPJ ' + fcShipTax : ''}`.trim(), st,
      st === 'REVISAR' ? 'Ship To (Factura) ≠ Consignee (BL/Booking)' : '', true);
  }
  campos.push(mkEntry('3', 'CONSIGNEE', 'comparacion', blConsignee, [c3ba, c3fc], { multiline: true }));

  // (4) NOTIFY PARTY ↔ universo notify del BA (estructurado + instrucciones) — match por CNPJ o email.
  //     Sub-línea intra-Booking (D8). Absorbe las filas legacy Notify Name/Tax/Email/BA⇒BL.
  const blNotify = buildBlock(bl.notify || '');
  const notifyTaxBL = norm14(cleanDigits((/(TAX\s*ID|CNPJ)\s*[: ]*\s*([0-9./-]+)/i.exec(String(bl.notify || '')) || [])[2] || ''));
  const notifyEmailBL = (String(bl.notify || '').match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig) || [])[0] || '';
  const nm = ba.notify_meta || {};
  const instrCnpjs = (Array.isArray(nm.notify_cnpjs_kept) ? nm.notify_cnpjs_kept : []).map(norm14);
  const baCnpjUniverse = [...new Set([norm14((nm.notify_structured && nm.notify_structured.cnpj) || ''), norm14((ba && ba.notify && ba.notify.tax_id) || ''), ...instrCnpjs].filter(Boolean))];
  const baEmailUniverse = [...new Set([((nm.notify_structured && nm.notify_structured.email) || ''), ((ba && ba.notify && ba.notify.email) || ''), ...((Array.isArray(nm.notify_emails_window) ? nm.notify_emails_window : []))].map(upper).filter(Boolean))];
  const matchCnpj = !!(notifyTaxBL && baCnpjUniverse.includes(notifyTaxBL));
  const matchEmail = !!(notifyEmailBL && baEmailUniverse.includes(upper(notifyEmailBL)));
  const anyBA = !!(baCnpjUniverse.length || baEmailUniverse.length);
  const baNotifyBlock = buildBlock(ba.notify || {});
  let c4 = null;
  if (baNotifyBlock || anyBA) {
    let st = 'NODATA', nota = '';
    if (anyBA && (notifyTaxBL || notifyEmailBL)) {
      if (matchCnpj || matchEmail) { st = 'OK'; nota = `Coincide por ${matchCnpj ? 'CNPJ' : 'email'} (empresa correcta); si el email puntual difiere, verificar la casilla`; }
      else { st = 'REVISAR'; nota = 'El notify del BL no coincide con NINGÚN notify del BA (estructurado ni instrucción)'; }
    } else if (anyBA) {
      // one-sided (espejo del criterio del (3)): el Booking declara notify y el BL no trae ninguno
      st = 'REVISAR'; nota = 'Notify ausente en el BL pese a estar declarado en el Booking — revisar';
    }
    c4 = comp('Booking', 'Booking (notify)', baNotifyBlock, st, nota, true);
  }
  const sub4 = (nm.notify_multiple || nm.notify_differ)
    ? { texto: 'Control intra-Booking · el BA declara notify distinto en el campo estructurado y en las instrucciones — validar cuál va', estado: 'REVISAR' }
    : (anyBA ? { texto: 'Control intra-Booking · notify estructurado e instrucciones del BA coinciden', estado: 'OK' } : null);
  campos.push(mkEntry('4', 'NOTIFY PARTY', 'comparacion', blNotify, [c4], { multiline: true, subs: [sub4] }));

  // (5) BOOKING NO. ↔ BA
  // G4 Tanda G: si bookingBA no contiene dígitos (pre-reserva "TBD", "PENDING", etc.) → NODATA informativo.
  const bookingBL = bl.booking_no || doc.booking_no || '';
  const bookingBA = ba.booking_no || ba.booking || '';
  const _bookingHasDigit = /\d/.test(bookingBA);
  campos.push(mkEntry('5', 'BOOKING NO.', 'comparacion', bookingBL, [
    bookingBA
      ? (_bookingHasDigit
          ? comp('Booking', 'Booking Advice', bookingBA, (bookingBL && bookingBL === bookingBA) ? 'OK' : 'REVISAR')
          : comp('Booking', 'Booking Advice', bookingBA, 'NODATA', `Booking Advice pre-reserva: sin booking asignado (valor '${bookingBA}')`))
      : null,
  ]));

  // (5A) BILL OF LADING NO. — solo BL
  campos.push(mkEntry('5A', 'BILL OF LADING NO.', 'informativo', bl.bl_no || bl.bl || '', []));

  // (6) EXPORT REFERENCES (orden) ↔ Aduana / Booking / Factura
  const orderBL = (Array.isArray(bl.export_references) && bl.export_references[0]) || bl.order_number || doc.order_number || '';
  const orderRefs = (Array.isArray(bl.export_references) && bl.export_references.length) ? bl.export_references.join(' / ') : orderBL;
  const orderBA = ba.order_number || '';
  const orderAD = adu.orden || adu.operacion || '';
  const eqOrd = (a, b) => !!(a && b) && stripLeadZeros(a) === stripLeadZeros(b);
  let stOrdAdu = orderAD ? (eqOrd(orderBL, orderAD) ? 'OK' : 'REVISAR') : 'NODATA', notaOrdAdu = '';
  if (adu.orden_multi && Array.isArray(adu.orden_candidatos) && adu.orden_candidatos.length > 1) {
    stOrdAdu = 'REVISAR';
    notaOrdAdu = `Planilla Aduana con ${adu.orden_candidatos.length} órdenes (${adu.orden_candidatos.join(', ')}); se usó ${orderAD} (del filename) — revisar manualmente`;
  }
  campos.push(mkEntry('6', 'EXPORT REFERENCES', 'comparacion', orderRefs, [
    (orderAD || stOrdAdu === 'REVISAR') ? comp('Aduana', 'Aduana', orderAD, stOrdAdu, notaOrdAdu) : null,
    orderBA ? comp('Booking', 'Booking', orderBA, eqOrd(orderBL, orderBA) ? 'OK' : 'REVISAR') : null,
    (fc && fc.order_number) ? comp('Factura', 'Factura', fc.order_number, eqOrd(orderBL, fc.order_number) ? 'OK' : 'REVISAR') : null,
  ]));

  // (7)/(9)/(9A)/(10)/(12)/(13)/(17): vacíos estructurales del formulario (10/10 raws en blanco).
  // Tanda C.1 — REGLA NUEVA: se ESPERAN vacíos; si la ventana inter-label del raw trae contenido
  // → REVISAR + triage ("posible error de carga"). Labels completos relevados del raw real; el
  // form lineariza labels adyacentes cuando el casillero está vacío.
  const VACIO_LBL = {
    '7':  /\(7\)\s*FORWARDING\s+AGENT\s*\/?\s*FMC\s+NO\.?/i,
    '9':  /\(9\)\s*ALSO\s+NOTIFY(?:\s+ROU[A-Z]*ING)?(?:\s*&\s*INSTRUCTIONS)?/i,
    '9A': /\(9A\)\s*FINAL\s+DESTINATION(?:\s*\(OF[^)]*\))?/i,
    '10': /\(10\)\s*LOADING\s+PIER\s*\/?\s*TERMINAL/i,
    '12': /\(12\)\s*PLACE\s+OF\s+RECEIPT/i,
    '13': /\(13\)\s*FINAL\s+PORT\s+OF\s+LOADING/i,
    '17': /\(17\)\s*PLACE\s+OF\s+DELIVERY/i,
  };
  const vacioConDato = (num) => {
    const t = String(doc.text || '');
    const m = t.match(VACIO_LBL[num]);
    if (!m) return '';                                     // sin raw o label ausente → como hoy
    const after = t.slice(m.index + m[0].length);
    const nxt = after.search(/\(\s*\d{1,2}A?\s*\)/);       // próximo label "(N)"/"(NA)" (tolera "(\n13)")
    let win = nxt >= 0 ? after.slice(0, nxt) : after.slice(0, 100);
    win = win.replace(/\([^)]*\)/g, ' ').replace(/[()]/g, ' ');
    // Ruido conocido: la marca de agua del BL DRAFT ("DRAFT COPY") cae dentro de la ventana
    // del (9) en los raws reales de LOG-IN — no es dato cargado. Se filtra ANTES de juzgar.
    win = win.replace(/\b(?:DRAFT\s+COPY|DRAFT|COPY|NON[-\s]?NEGOTIABLE)\b/gi, ' ');
    win = win.replace(/\s+/g, ' ').trim();
    return win;
  };
  const mkVacio = (num, titulo) => {
    const dato = vacioConDato(num);
    if (!dato) return mkEntry(num, titulo, 'vacio', '', []);
    return mkEntry(num, titulo, 'comparacion', dato, [], { subs: [{
      texto: `El (${num}) debería ir vacío y vino con dato ("${dato.slice(0, 60)}") — posible error de carga`,
      estado: 'REVISAR' }] });
  };
  campos.push(mkVacio('7', 'FORWARDING AGENT / FMC NO.'));

  // (8) POINT AND COUNTRY — derivado del raw del BL (D4)
  const p8 = pointAndCountryFromText(doc.text);
  campos.push(mkEntry('8', 'POINT AND COUNTRY', p8 ? 'informativo' : 'vacio', p8, []));

  campos.push(mkVacio('9', 'ALSO NOTIFY / INSTRUCTIONS'));
  campos.push(mkVacio('9A', 'FINAL DESTINATION'));
  campos.push(mkVacio('10', 'LOADING PIER / TERMINAL'));

  // (10A) ORIGINALS TO BE RELEASED AT ↔ release point del RAW del BA (Tanda C.1 — regex, SIN IA).
  // BA declara → comparación (BL DESTINO/ORIGEN vs BA); difiere o contradicción → REVISAR;
  // BA no lo indica → informativo (como hoy).
  const blOriginals = String(bl.originals_to_be_released_at || (bl.desc && bl.desc['DESC BL - ORIGINALS TO BE RELEASED AT']) || '').trim();
  const orl = (ba && ba.originals_release) || { value: '', conflict: false };
  const normRel = (s) => { const u = upper(s); return /DESTIN/.test(u) ? 'DESTINO' : (/ORIG/.test(u) ? 'ORIGEN' : u); };
  let c10a = null;
  if (orl.conflict) {
    c10a = comp('Booking', 'Booking (instrucciones)', 'indicaciones contradictorias', 'REVISAR',
      'El BA trae indicaciones contradictorias de dónde se liberan los originales — revisar');
  } else if (orl.value) {
    const okR = !!blOriginals && normRel(blOriginals) === orl.value;
    const st = okR ? 'OK' : 'REVISAR';
    c10a = comp('Booking', 'Booking (instrucciones)', orl.value, st,
      st === 'REVISAR' ? (blOriginals
        ? `Originales: BL ${normRel(blOriginals)} ≠ Booking ${orl.value} — verificar dónde se liberan los originales`
        : `El BA indica ${orl.value} y el BL no trae el (10A) — verificar`) : '');
  }
  campos.push(mkEntry('10A', 'ORIGINALS TO BE RELEASED AT', c10a ? 'comparacion' : 'informativo', blOriginals, [c10a]));

  campos.push(mkEntry('11', 'TYPE OF MOVE', 'informativo', bl.type_of_move || (bl.desc && bl.desc['DESC BL - TYPE OF MOVE']) || '', []));
  campos.push(mkVacio('12', 'PLACE OF RECEIPT'));
  campos.push(mkVacio('13', 'FINAL PORT OF LOADING'));

  // (14) VESSEL VOYAGE ↔ Aduana.buque — INFORMATIVO SIEMPRE (Aduana puede traer feeder; regla vigente)
  const vesselBL = `${bl.vessel || ''} ${bl.voyage || ''}`.trim();
  campos.push(mkEntry('14', 'VESSEL VOYAGE', 'informativo', vesselBL,
    [adu.buque ? comp('Aduana', 'Aduana', adu.buque, 'INFO') : null],
    { nota: 'Informativo — Aduana puede traer el feeder/buque distinto al del BL; no marca estado' }));

  // (15)/(16) POL/POD ↔ Booking (pasan de informativo a COMPARAR — mapping aprobado)
  campos.push(mkEntry('15', 'PORT OF LOADING', 'comparacion', bl.pol || '',
    [(ba.pol || ba.POL) ? comp('Booking', 'Booking (POL)', ba.pol || ba.POL, (bl.pol ? (eqPort(bl.pol, ba.pol || ba.POL) ? 'OK' : 'REVISAR') : 'NODATA')) : null]));
  campos.push(mkEntry('16', 'PORT OF DISCHARGE', 'comparacion', bl.pod || '',
    [(ba.pod || ba.POD) ? comp('Booking', 'Booking (POD)', ba.pod || ba.POD, (bl.pod ? (eqPort(bl.pod, ba.pod || ba.POD) ? 'OK' : 'REVISAR') : 'NODATA')) : null]));

  campos.push(mkVacio('17', 'PLACE OF DELIVERY'));

  /* ================= TOTALES Y CONTROLES (debajo del 17) ================= */
  const totales = [];
  const numCompare = (vals, fmt, titulo) => {
    // vals = [{doc,label,val}] con BL primero; referencia = BL si declara, si no la primera fuente presente
    const n0 = toNum(vals[0].val);
    const present = vals.map((v) => toNum(v.val)).filter((n) => n != null && n !== 0);
    const ref = (n0 != null && n0 !== 0) ? n0 : (present.length ? present[0] : null);
    const comps = vals.slice(1).map((v) => {
      const n = toNum(v.val);
      if (n == null || n === 0) return comp(v.doc, v.label, '', 'NODATA');
      return comp(v.doc, v.label, v.val, (ref == null || n === ref) ? 'OK' : 'REVISAR');
    });
    return mkEntry('', titulo, 'comparacion', (n0 != null && n0 !== 0) ? vals[0].val : '', comps, { fmt });
  };

  totales.push(numCompare([
    { doc: 'BL', label: 'BL', val: bl.desc && bl.desc['DESC BL - PESO NETO TOTAL (KG)'] },
    { doc: 'Aduana', label: 'Aduana', val: adu.totals && adu.totals.neto },
    { doc: 'Booking', label: 'Booking', val: ba.totales && ba.totales.net_kg },
    { doc: 'Factura', label: 'Factura', val: fc.totals && fc.totals.net },
  ], 'kg', 'Peso Neto Total (KG)'));
  totales.push(numCompare([
    { doc: 'BL', label: 'BL', val: bl.desc && bl.desc['DESC BL - PESO BRUTO TOTAL (KG)'] },
    { doc: 'Aduana', label: 'Aduana', val: adu.totals && adu.totals.bruto },
    { doc: 'Booking', label: 'Booking', val: ba.totales && ba.totales.gross_kg },
    { doc: 'Factura', label: 'Factura', val: fc.totals && fc.totals.gross },
  ], 'kg', 'Peso Bruto Total (KG)'));

  // Bolsas y Pallets totales — v7: 4 fuentes visibles (BL · Aduana · Booking · Factura).
  // Aduana no declara bolsas y el Booking no declara pallets → caja "—" (NODATA estructural,
  // nunca REVISAR). La Factura entra como fuente NUEVA (suma de items[]): solo flaggea si
  // declara y difiere del BL; ausente → NODATA (sin REVISAR espurio). La semántica one-sided
  // BL↔BA (bolsas) y BL↔Aduana (pallets) se preserva EXACTA (matriz: 0 señales perdidas).
  const bolsasBL = (bl.desc && bl.desc['DESC BL - CANTIDAD DE BOLSAS']) ?? '';
  const bolsasBA = (ba.totales && ba.totales.piece_count) ?? '';
  // Tanda BULK (gate B bolsas): bulk → ambos lados ausentes → NODATA "—" (D1).
  // El BL declara 0 bolsas (no '') y el BA declara piece_count en KG = peso neto →
  // estos ceros dispararían REVISAR falso. El gate los trata como ausentes.
  const stBolsas = isBulk ? 'NODATA'
    : ((String(bolsasBL) !== '' && String(bolsasBA) !== '')
      ? (String(bolsasBL) === String(bolsasBA) ? 'OK' : 'REVISAR')
      : ((String(bolsasBL) !== '' || String(bolsasBA) !== '') ? 'REVISAR' : 'NODATA'));
  const fcItemsTot = Array.isArray(fc.items) ? fc.items : [];
  const fcBagsTot = fcItemsTot.reduce((s, it) => s + (it ? (toNum(it.bags) || 0) : 0), 0);
  const fcPalletsTot = fcItemsTot.reduce((s, it) => s + (it ? (toNum(it.pallets) || 0) : 0), 0);
  const stNumVsBL = (blRaw, n) => { const b = toNum(blRaw); return (b != null && b !== 0) ? (b === n ? 'OK' : 'REVISAR') : 'NODATA'; };
  // Tanda BULK — fila informativa Piece Count (KG) solo si isBulk y unit==='KG'.
  // Compara piece_count vs net_kg: si son iguales → OK informativo; si difieren → REVISAR real.
  const pcUnit = (ba.totales && ba.totales.piece_count_unit) || null;
  const pcVal = ba.totales && ba.totales.piece_count;
  const netVal = ba.totales && ba.totales.net_kg;
  // Condición: unit==='KG', o bien isBulk y piece_count==net_kg numéricamente (fixtures viejos sin unit)
  const showPieceCountKg = isBulk && (pcUnit === 'KG'
    || (pcUnit == null && pcVal != null && netVal != null && toNum(pcVal) === toNum(netVal)));
  let pieceCountKgEntry = null;
  if (showPieceCountKg) {
    const pcN = toNum(pcVal), netN = toNum(netVal);
    const eqPC = (pcN != null && netN != null && pcN === netN);
    const stPC = eqPC ? 'OK' : 'REVISAR';
    pieceCountKgEntry = mkEntry('', 'Piece Count (BA)', 'comparacion', pcVal != null ? String(pcVal) : '', [
      comp('Booking', 'Booking (Piece Count vs Neto)', netVal != null ? String(netVal) : '', stPC,
        stPC === 'OK' ? 'Piece Count del BA en KG = peso neto' : 'Piece Count del BA (KG) ≠ peso neto — revisar'),
    ], { fmt: 'num' });
  }
  totales.push(mkEntry('', 'Bolsas totales', 'comparacion',
    isBulk ? '' : bolsasBL,
    isBulk ? [
      comp('Aduana',   'Aduana',   '', 'NODATA'),
      comp('Booking',  'Booking',  '', 'NODATA'),
      comp('Factura',  'Factura',  '', 'NODATA'),
    ] : [
      comp('Aduana', 'Aduana', '', 'NODATA'),
      comp('Booking', 'Booking', bolsasBA, stBolsas, stBolsas === 'REVISAR' ? 'BL vs Booking Advice (bolsas)' : ''),
      fcBagsTot > 0
        ? comp('Factura', 'Factura', fcBagsTot, stNumVsBL(bolsasBL, fcBagsTot), stNumVsBL(bolsasBL, fcBagsTot) === 'REVISAR' ? 'BL vs Factura (bolsas)' : '')
        : comp('Factura', 'Factura', '', 'NODATA'),
    ], { fmt: 'num' }));
  if (pieceCountKgEntry) totales.push(pieceCountKgEntry);

  const palletsBL = (bl.desc && bl.desc['DESC BL - CANTIDAD DE PALLETS']) ?? '';
  const palletsAD = (adu.totals && adu.totals.bultos) ?? '';
  // Tanda BULK (gate C pallets): "Aduana 5" = adu.totals.bultos, que en la planilla de Aduana
  // para bulk NO son pallets sino la cantidad de contenedores (5 bulk containers). El BL declara
  // 0 pallets (no los hay). Gate: isBulk → NODATA + sub-check informativo N bultos = N contenedores.
  // La fuente del "Aduana 5" es adu.totals.bultos (L771 del original), que viene de la planilla
  // de Aduana como campo "bultos" de totales — en bulk, la planilla pone 5 (= nro de contenedores).
  const stPallets = isBulk ? 'NODATA'
    : ((String(palletsBL) !== '' && String(palletsAD) !== '')
      ? (String(palletsBL) === String(palletsAD) ? 'OK' : 'REVISAR')
      : ((String(palletsBL) !== '' || String(palletsAD) !== '') ? 'REVISAR' : 'NODATA'));
  // Sub-check bulk: aduana.totals.bultos == count(contenedores de la planilla) == count(equipos BL)
  let subPalletsBulk = null;
  if (isBulk) {
    const aduBultos = toNum(palletsAD);
    const aduConts = Array.isArray(adu.contenedores) ? adu.contenedores.length : null;
    const blConts = Array.isArray(bl.equipos) ? bl.equipos.length : null;
    // Comparar las fuentes disponibles: aduana vs conteos de lista de contenedores
    const refConts = aduConts != null ? aduConts : blConts;
    // Informativo, NUNCA REVISAR (decisión John): si coincide → sub OK ✓; si difiere se OMITE
    // (la plantilla compartida sufija "— OK ✓" a todo sub no-REVISAR, y un "≠ ... OK ✓" sería
    // contradictorio; emitir REVISAR escalaría el badge, que es lo que este sub no debe hacer).
    if (aduBultos != null && refConts != null && aduBultos === refConts) {
      subPalletsBulk = {
        texto: `Aduana declara ${aduBultos} bultos = ${refConts} contenedores ✓`,
        estado: 'OK',
      };
    }
  }
  totales.push(mkEntry('', 'Pallets totales', 'comparacion',
    isBulk ? '' : palletsBL,
    isBulk ? [
      comp('Aduana',   'Aduana (bultos)',  '', 'NODATA'),
      comp('Booking',  'Booking',          '', 'NODATA'),
      comp('Factura',  'Factura',          '', 'NODATA'),
    ] : [
      comp('Aduana', 'Aduana (bultos)', palletsAD, stPallets, stPallets === 'REVISAR' ? 'BL vs Aduana (pallets)' : ''),
      comp('Booking', 'Booking', '', 'NODATA'),
      fcPalletsTot > 0
        ? comp('Factura', 'Factura', fcPalletsTot, stNumVsBL(palletsBL, fcPalletsTot), stNumVsBL(palletsBL, fcPalletsTot) === 'REVISAR' ? 'BL vs Factura (pallets)' : '')
        : comp('Factura', 'Factura', '', 'NODATA'),
    ], { fmt: 'num', subs: subPalletsBulk ? [subPalletsBulk] : [] }));

  // HS/NCM (4 dígitos) ↔ BA hs.import/ncm_export + Factura items[].product_code (prefijo 4)
  // PE (decisión #4): gate prefix4 con pata PE (set de posiciones SIM, dedupe) + sub-check full PE↔FC.
  const ncmBL = prefix4(bl.desc && bl.desc['DESC BL - NCM']);
  const baNcmRaw = (ba.hs && ba.hs.import) || ba.ncm_export || '';
  const fcCodes = [...new Set((Array.isArray(fc.items) ? fc.items : []).map((it) => it && it.product_code).filter(Boolean))];
  const peCodesFull = pe ? [...new Set((Array.isArray(pe.items) ? pe.items : []).map((it) => normPA(it && it.posicion_sim)).filter(Boolean))] : [];
  const peCodes4 = [...new Set(peCodesFull.map((c) => cleanDigits(c).slice(0, 4)))];   // consistente con prefix4(ncmBL)
  const fcCodesFull = [...new Set(fcCodes.map((c) => normPA(c)).filter(Boolean))];
  // sub-check FUERTE: posición completa PE↔Factura (ambos la traen full; BL queda en el gate de 4 díg)
  let subPA = null;
  if (pe && peCodesFull.length && fcCodesFull.length) {
    const setEq = peCodesFull.length === fcCodesFull.length && peCodesFull.every((c) => fcCodesFull.includes(c));
    subPA = { texto: `Posición arancelaria completa PE↔Factura: {${peCodesFull.join(', ')}} vs {${fcCodesFull.join(', ')}}`, estado: setEq ? 'OK' : 'REVISAR' };
  }
  totales.push(mkEntry('', 'HS / NCM (4 dígitos)', 'comparacion', ncmBL ? ncmBL : (bl.desc && bl.desc['DESC BL - NCM']) || '', [
    comp('Aduana', 'Aduana', '', 'NODATA'),
    baNcmRaw ? comp('Booking', 'Booking', baNcmRaw, ncmBL ? (prefix4(baNcmRaw) === ncmBL ? 'OK' : 'REVISAR') : 'NODATA') : null,
    fcCodes.length ? comp('Factura', 'Factura', fcCodes.join(' · '), ncmBL ? (fcCodes.every((c) => prefix4(c) === ncmBL) ? 'OK' : 'REVISAR') : 'NODATA') : null,
    peCodes4.length ? comp('PE', 'PE', peCodesFull.join(' · '), ncmBL ? (peCodes4.every((c) => c === ncmBL) ? 'OK' : 'REVISAR') : 'NODATA') : null,
  ], { subs: subPA ? [subPA] : [] }));

  // Permiso de Embarque (PE) — BL-anchored: BL/Aduana/Factura + PE doc (Destinación SIM).
  // Decisión #1: sin PE doc → cruce actual BL↔Aduana↔FC intacto (peDocPE='' → pata null → filtrada).
  // Con PE doc → la pata PE compara la Destinación SIM contra el permiso del BL (cruce #1: BL == PE).
  const blPE = normPE((bl.desc && bl.desc['DESC BL - PE (PERMISO DE EMBARQUE)']) || '');
  const aduPE = normPE(adu.ddt || adu.pe || '');
  const fcPE = normPE(fc.shipping_permit || '');
  const peDocPE = pe ? normPE(pe.destinacion_sim || '') : '';
  const peRef = blPE || aduPE || fcPE || peDocPE;   // ancla = BL si declara (tabla BL-anchored)
  const peComp = (docName, v) => v ? comp(docName, docName, v, v === peRef ? 'OK' : 'REVISAR') : null;
  totales.push(mkEntry('', 'Permiso de Embarque (PE)', 'comparacion', blPE,
    [peComp('Aduana', aduPE), peComp('Factura', fcPE), peComp('PE', peDocPE)],
    { nota: (new Set([blPE, aduPE, fcPE, peDocPE].filter(Boolean))).size > 1 ? 'Permiso de Embarque difiere entre documentos' : '' }));

  // Embalaje — fuente BL derivada (campo extraído muerto 0/51) ↔ BA producto.embalaje + FC items[].embalaje
  // H1 (Tanda H): bulk orders → blEmb fijo 'Bulk' (evita NODATA/REVISAR en embalaje para estas órdenes).
  const blEmb = isBulk ? 'Bulk'
    : (String((bl.desc && bl.desc['DESC BL - TIPO DE EMBALAJE']) || '').trim() || (/\bBAGS?\b/i.test(bl.goods_block_raw || '') ? 'Bags' : ''));
  const baEmb = (ba.producto && ba.producto.embalaje) || '';
  const fcEmb = ((Array.isArray(fc.items) ? fc.items : []).map((it) => it && it.embalaje).filter(Boolean))[0] || '';
  totales.push(mkEntry('', 'Embalaje', 'comparacion', blEmb, [
    baEmb ? comp('Booking', 'Booking', baEmb, blEmb ? (eqEmb(blEmb, baEmb) ? 'OK' : 'REVISAR') : 'NODATA') : null,
    fcEmb ? comp('Factura', 'Factura', fcEmb, blEmb ? (eqEmb(blEmb, fcEmb) ? 'OK' : 'REVISAR') : 'NODATA') : null,
  ], { nota: (blEmb && !(bl.desc && bl.desc['DESC BL - TIPO DE EMBALAJE'])) ? 'BL: derivado del bloque de mercadería' : '' }));

  // Destino (País) — control propio (D5) BL/Aduana/Booking/Factura + sub-chequeos de incoterm (D3)
  // PLANCOMPLETO-D-DESTINO (2026-07-15, decisión §5.12 "destino en tránsito NO es
  // error" — caso real Arica/Tacna): el lado BL aporta el país del TRÁNSITO (POD /
  // consignee), mientras Aduana/Booking/Factura declaran el destino FINAL. Comparar
  // esos dos niveles como si fueran el mismo dato era el falso positivo (EXPLORE B4a).
  // Regla nueva: las fuentes de destino FINAL (Aduana/Booking/Factura) se comparan
  // ENTRE SÍ (difieren → REVISAR — sigue cazando el error de planilla, p.ej. Aduana
  // Brasil vs Booking Perú); el país del BL que difiera del consenso final NO marca
  // REVISAR: baja a sub-chequeo INFO "destino en tránsito".
  const blPais = bl.destino_pais || paisFromText(bl.consignee || '');
  const aduPais = adu.destino || '';
  const baPais = ba.destino_pais || ba.country || '';
  const fcPais = (fc && fc.country) || '';
  const finalCanons = [aduPais, baPais, fcPais].map(canonCountry).filter(Boolean);
  const finalBase = finalCanons.length ? finalCanons[0] : null;
  const finalDiff = finalCanons.length >= 2 && new Set(finalCanons).size > 1;
  const blCanon = canonCountry(blPais);
  // paisDiff conserva su rol de "hay algo que mirar" para la nota, pero SOLO entre finales
  const paisDiff = finalDiff;
  const stPais = (v) => v ? (finalDiff ? (canonCountry(v) === finalBase ? 'OK' : 'REVISAR') : 'OK') : 'NODATA';
  const transito = !!(blCanon && finalBase && blCanon !== finalBase && !finalDiff);
  const subsDestino = [];
  const ofKind = getOceanFreightKindFromBL(bl);
  const bucket = expectedIncotermBucketByFreight(ofKind);
  const incShown = upper(ba.incoterm).slice(0, 3) || upper(fc.incoterm || '').slice(0, 3);
  if (bucket && incShown) {
    const okB = bucket.allowed.has(incShown.charAt(0));
    subsDestino.push({ texto: `Incoterm ${incShown} vs Ocean Freight del BL (${ofKind} ⇒ esperado ${bucket.label})`, estado: okB ? 'OK' : 'REVISAR' });
  } else if (bucket && !incShown) {
    subsDestino.push({ texto: `BA/FC sin Incoterm y el BL indica Ocean Freight ${ofKind} (esperado ${bucket.label})`, estado: 'REVISAR' });
  }
  const fcIncoterm = upper(fc.incoterm || '').slice(0, 3);
  const fcPlace = stripPortName(fc.incoterm_place || '');
  if (fcIncoterm && fcPlace) {
    // v7: el place de la Factura valida el puerto del BL según el grupo del incoterm —
    // C/D → Port of Discharge (16); E/F (ej. FOB) → Port of Loading (15). Cruce explícito.
    const grupoCD = (fcIncoterm.charAt(0) === 'C' || fcIncoterm.charAt(0) === 'D');
    const target = grupoCD ? (bl.pod || '') : (bl.pol || '');
    if (target) {
      const okP = eqPort(fcPlace, target);
      subsDestino.push({ texto: `La Factura es el ancla del cruce (aporta incoterm + consignee + país) · Incoterm ${fcIncoterm} (grupo ${grupoCD ? 'C/D' : 'E/F'}) → el place de la Factura (${fcPlace}) valida el ${grupoCD ? 'Port of Discharge (16)' : 'Port of Loading (15)'}: ${okP ? 'coincide con' : 'NO coincide con'} el ${grupoCD ? 'POD' : 'POL'} del BL (${upper(target)})`, estado: okP ? 'OK' : 'REVISAR' });
    }
  }
  // v7: la caja Factura muestra país + incoterm CON su place ("BRAZIL · Incoterm CFR NAVEGANTES").
  const fcDestinoShow = [fcPais ? canonCountry(fcPais) : '', fcIncoterm ? `Incoterm ${fcIncoterm}${fcPlace ? ' ' + fcPlace : ''}` : ''].filter(Boolean).join(' · ');
  // Destino en tránsito (decisión §5.12): INFO explícita, jamás REVISAR.
  if (transito) {
    subsDestino.push({
      texto: `Destino en tránsito: el BL llega a ${blCanon}${bl.pod ? ` (POD ${upper(bl.pod)})` : ''} y el destino final declarado es ${finalBase} (Booking/Aduana/Factura) — la carga sigue en tránsito terrestre. No es un error (regla de negocio).`,
      estado: 'OK',
    });
  }
  totales.push(mkEntry('', 'Destino (País) · Incoterm', 'comparacion', blPais ? canonCountry(blPais) : '', [
    aduPais ? comp('Aduana', 'Aduana', canonCountry(aduPais), stPais(aduPais)) : null,
    baPais ? comp('Booking', 'Booking', canonCountry(baPais), stPais(baPais)) : null,
    fcDestinoShow ? comp('Factura', 'Factura', fcDestinoShow, fcPais ? stPais(fcPais) : 'NODATA') : null,
  ], { subs: subsDestino, nota: paisDiff ? 'El destino FINAL difiere entre Aduana/Booking/Factura (normalizado)' : (transito ? 'POD en tránsito — destino final en otro país (dato del Booking)' : '') }));

  /* ================= FACTURA: flete (control vive en la tabla de tarifa; acá solo counter+aviso) ===== */
  const fcInc3 = upper(fc.incoterm || '');
  const fcFreight = toNum(fc.freight_usd);
  const blPrepaidUSD = toNum(bl && bl.freight && bl.freight.totals && bl.freight.totals.USD && bl.freight.totals.USD.prepaid);
  let fleteAviso = null;
  // Decisión #1: SIN PE doc → cruce flete actual (FC↔BL) EXACTO (byte-idéntico para órdenes sin PE).
  if (!pe && fc && Object.keys(fc).length && RE_FLETE_PREPAID.test(fcInc3)) {
    let stF = 'OK';
    if (fcFreight != null && blPrepaidUSD != null) {
      stF = Math.round(fcFreight) === Math.round(blPrepaidUSD) ? 'OK' : 'REVISAR';
      if (stF === 'REVISAR') fleteAviso = `Flete FC (${fcFreight}) ≠ prepaid USD del BL (${blPrepaidUSD}) — crítico, error en BL cuesta`;
    } else { stF = 'REVISAR'; fleteAviso = 'Incoterm con flete incluido pero falta el monto en FC o BL'; }
    bump(stF);
  }

  /* ===== PE work-stream — cruces de valores económicos (filas NUEVAS, SÓLO si hay PE doc) =====
     #5 FOB total PE↔FC (sólo total, decisión #9) · #3 flete 3-way BL prepaid/FC freight_total/PE (decisión #2/#3) ·
     #4 seguro PE↔FC sólo CIF/CIP (decisión #5) · incoterm PE↔FC · #7 reasignación FOB/flete consolidada.
     mkEntry (auto-bump + auto-render + auto-triage). Sin PE: nada corre → salida byte-idéntica. */
  if (pe) {
    const peFob = numSafe(pe.fob_total), fcFob = numSafe(fc.fob_usd);
    const peFlete = numSafe(pe.flete_total);
    const fcFlete = numSafe(fc.freight_total != null ? fc.freight_total : fc.freight_usd);   // canónico: freight_total
    const peSeg = numSafe(pe.seguro_total), fcSeg = numSafe(fc.insurance_usd);
    const eqR = (a, b) => (a != null && b != null) ? (Math.round(a) === Math.round(b)) : null;
    const eqR2 = (a, b) => (a != null && b != null) ? (Math.round(a * 100) === Math.round(b * 100)) : null;
    // Fila de valor PE↔FC(+BL): las comparaciones SÓLO muestran valor (estado 'OK' = mostrar; el ámbar
    // es del estado de fila). El veredicto + mensaje van en UN sub → 1 ítem de triage por fila (decisión #7).
    const peRow = (titulo, blAnchor, comps, rev, msg) =>
      totales.push(mkEntry('', titulo, 'comparacion', blAnchor == null ? '' : blAnchor,
        comps.filter(Boolean), { fmt: 'num', subs: rev ? [{ texto: msg, estado: 'REVISAR' }] : [] }));

    // #7 reasignación compensada: total (FOB+flete+seguro) PE == FC pero FOB y flete redistribuidos
    let joint = false;
    if (peFob != null && peFlete != null && fcFob != null && fcFlete != null) {
      const peTot = peFob + peFlete + (peSeg || 0), fcTot = fcFob + fcFlete + (fcSeg || 0);
      joint = Math.round(peTot) === Math.round(fcTot)
        && Math.round(peFob) !== Math.round(fcFob) && Math.round(peFlete) !== Math.round(fcFlete);
    }

    if (joint) {
      const txt = `Reasignación FOB/flete en el PE: el total coincide con la Factura, pero los montos están redistribuidos — PE FOB ${peFob} / flete ${peFlete} vs Factura FOB ${fcFob} / flete ${fcFlete}. Verificar el permiso (flete mal cargado tiene costo).`;
      peRow('FOB / Flete (PE↔Factura)', '',
        [comp('Factura', 'Factura', `FOB ${fcFob} · flete ${fcFlete}`, 'OK'),
         comp('PE', 'PE', `FOB ${peFob} · flete ${peFlete}`, 'OK')], true, txt);
    } else {
      // #5 FOB total (sólo total — decisión #9; NO por posición)
      if (peFob != null || fcFob != null) {
        const rev = eqR(peFob, fcFob) === false;
        peRow('FOB total (USD)', '',
          [fcFob != null ? comp('Factura', 'Factura', fcFob, 'OK') : null, peFob != null ? comp('PE', 'PE', peFob, 'OK') : null],
          rev, `FOB total PE (${peFob}) ≠ Factura (${fcFob})`);
      }
      // #3 flete 3-way (BL prepaid / FC freight_total / PE flete) — sólo incoterm prepaid (regex único)
      if (RE_FLETE_PREPAID.test(fcInc3)) {
        const fv = [['BL', blPrepaidUSD], ['Factura', fcFlete], ['PE', peFlete]].filter(([d, v]) => v != null);
        // lenient (consistente con FOB): REVISAR sólo si ≥2 valores presentes difieren; faltante → OK (no penaliza gap)
        const rev = fv.length >= 2 && new Set(fv.map(([d, v]) => Math.round(v))).size !== 1;
        peRow('Flete total (USD)', blPrepaidUSD != null ? blPrepaidUSD : '',
          [fcFlete != null ? comp('Factura', 'Factura', fcFlete, 'OK') : null, peFlete != null ? comp('PE', 'PE', peFlete, 'OK') : null],
          rev, `Flete difiere entre BL/Factura/PE (${fv.map(([d, v]) => `${d} ${v}`).join(' / ')}) — crítico`);
      }
    }
    // #4 seguro PE↔FC — sólo CIF/CIP (decisión #5)
    if (RE_SEGURO_INC.test(fcInc3)) {
      // lenient (decisión #1 / consistencia con FOB): REVISAR sólo si ambos presentes y difieren;
      // si falta seguro en PE o FC, NO se fuerza REVISAR (gap de dato, no discrepancia).
      const rev = eqR2(peSeg, fcSeg) === false;
      peRow('Seguro (USD)', '',
        [fcSeg != null ? comp('Factura', 'Factura', fcSeg, 'OK') : null, peSeg != null ? comp('PE', 'PE', peSeg, 'OK') : null],
        rev, `Seguro PE (${peSeg}) ≠ Factura (${fcSeg}) — verificar póliza`);
    }
    // incoterm consistency PE↔FC (cond_venta vs incoterm)
    if (pe.cond_venta && fc.incoterm) {
      const a = upper(pe.cond_venta).slice(0, 3), b = fcInc3.slice(0, 3);
      if (a && b && a !== b) peRow('Incoterm (PE↔Factura)', '',
        [comp('Factura', 'Factura', b, 'OK'), comp('PE', 'PE', a, 'OK')], true, `Incoterm difiere: PE ${a} ≠ Factura ${b}`);
    }
  }

  /* ================= PRODUCTOS (Tanda B + gate bulk) ================= */
  const prod = buildProductos(bl, fc, adu, ba, isBulk);
  counters.REVISAR += prod.revisar; counters.OK += (prod.count - prod.revisar);
  const header_badges = buildHeaderBadges(bl, fc, prod);
  const compare_productos_summary = { overall: prod.revisar > 0 ? 'REVISAR' : 'OK', count: prod.count, multiproducto: prod.multiproducto, revisar: prod.revisar };

  /* ================= EQUIPOS (+ meta de lista, D2) ================= */
  const eq = buildCompareEquipos(bl, ba, adu, palletsBL);
  if (eq.meta && eq.meta.notas.length) bump('REVISAR'); else bump('OK');

  /* ================= AVISOS / GUARD ================= */
  const proactive_comments = buildProactiveComments(doc, bl, ba, fc, header_badges).concat(prod.avisos || []);
  // Sold To (D4): sin fila propia — badge TRIANGULAR + aviso si BA y FC difieren.
  const baSoldTax = norm14((nm.sold_to && nm.sold_to.tax) || '');
  const fcSoldTax = norm14((fc && fc.sold_to && fc.sold_to.tax) || '');
  if (baSoldTax && fcSoldTax && baSoldTax !== fcSoldTax) {
    proactive_comments.push({ doc: 'Factura', level: 'warn', text: `Sold To difiere entre Booking (${baSoldTax}) y Factura (${fcSoldTax}) — revisar.` });
    bump('REVISAR');
  }
  if (fleteAviso) proactive_comments.push({ doc: 'Factura', level: 'warn', text: fleteAviso });
  const missing_docs = buildGuard(doc);

  /* ================= TRIAGE (Tanda C.1) — blanco de escaneo del mail v10 =================
     DERIVADO de las señales existentes: NO altera estados/counters/bump (la matriz de
     equivalencia sigue leyendo campos/totales/equipos/productos como siempre).
     Orden fijo: SECCIÓN 1 → SECCIÓN 2 → CONTENEDORES → FLETE → DOCUMENTOS.
     Formato v10 por ítem: { seccion, campo, titulo (negrita), detalle ("BL X ≠ Doc Y → acción") }. */
  const fmtT = (n) => { const x = toNum(n); if (x == null) return String(n == null ? '' : n);
    const p = Math.abs(x).toFixed(Math.abs(x) % 1 ? 2 : 0).split('.');
    return (x < 0 ? '-' : '') + p[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.') + (p[1] ? ',' + p[1] : ''); };
  const line1 = (s, n) => { const t = String(s == null ? '' : s).split('\n')[0].trim(); const max = n || 64; return t.length > max ? t.slice(0, max - 1) + '…' : t; };
  const buckets = { 'SECCIÓN 1': [], 'SECCIÓN 2': [], 'CONTENEDORES': [], 'FLETE': [], 'DOCUMENTOS': [] };
  const tPush = (sec, campo, titulo, detalle) => buckets[sec].push({ seccion: sec, campo, titulo, detalle: detalle || '' });
  const entryItems = (f, sec, campoLbl) => {
    for (const c of (f.comparaciones || [])) {
      if (c.estado !== 'REVISAR') continue;
      const titulo = c.nota ? (c.nota + '.') : `${f.titulo}: difiere entre el BL y ${c.doc}.`;
      const det = `BL ${line1(f.bl.valor) || '(vacío)'} ≠ ${c.doc} ${line1(c.valor) || '(vacío)'} → verificar.`;
      tPush(sec, campoLbl, titulo, det);
    }
    for (const s of (f.subs || [])) if (s.estado === 'REVISAR') tPush(sec, campoLbl, s.texto + '.', '');
  };
  for (const f of campos) if (f.estado === 'REVISAR') entryItems(f, 'SECCIÓN 1', `(${f.num}) ${f.titulo}`);
  for (const f of totales) if (f.estado === 'REVISAR')
    entryItems(f, f.titulo === 'Destino (País) · Incoterm' ? 'SECCIÓN 1' : 'SECCIÓN 2', f.titulo);
  // Productos (filas REVISAR) — el cartel del despachante en formato triage
  for (const p of prod.rows) {
    if (p.estado !== 'REVISAR') continue;
    if (Array.isArray(p.nombre_difiere) && p.nombre_difiere.length) {
      // G6 Tanda G: referencia = primer doc presente NO en nombre_difiere (BL→FC→Adu→BA); fallback = grade
      const _refCands = [['BL', p.BL && p.BL.goods], ['Factura', p.FC && p.FC.desc], ['Aduana', p.Adu && p.Adu.prod], ['Booking', p.BA && p.BA.cadena]];
      let _refDoc = 'Grado', _refVal = p.grade;
      for (const [_d, _v] of _refCands) { if (!p.nombre_difiere.includes(_d) && _v) { _refDoc = _d; _refVal = _v; break; } }
      const others = p.nombre_difiere.map((d) => `${d} "${line1(d === 'Aduana' ? (p.Adu && p.Adu.prod) : d === 'Booking' ? (p.BA && p.BA.cadena) : d === 'Factura' ? (p.FC && p.FC.desc) : (p.BL && p.BL.goods)) || '—'}"`).join(' · ');
      tPush('SECCIÓN 2', 'Producto', `Nombre del producto difiere en ${p.nombre_difiere.join(', ')}.`,
        `${_refDoc} "${line1(_refVal)}" ≠ ${others} → verificar con el despachante.`);
    }
    if (p.diffs && Array.isArray(p.diffs.faltan) && p.diffs.faltan.length)
      tPush('SECCIÓN 2', 'Producto', `Producto ${p.grade}: sin contraparte en ${p.diffs.faltan.map((d) => DOC_LABEL[d]).join(', ')}.`,
        'Verificar que el producto figure en todos los documentos.');
    const mags = [];
    if (p.diffs && p.diffs.net) mags.push(`Neto BL ${fmtT(p.BL && p.BL.net)} / Aduana ${fmtT(p.Adu && p.Adu.net)} / FC ${fmtT(p.FC && p.FC.net)} kg`);
    if (p.diffs && p.diffs.gross) mags.push(`Bruto BL ${fmtT(p.BL && p.BL.gross)} / Aduana ${fmtT(p.Adu && p.Adu.gross)} / FC ${fmtT(p.FC && p.FC.gross)} kg`);
    if (p.diffs && p.diffs.bags) mags.push(`Bolsas BL ${fmtT(p.BL && p.BL.bags)} / FC ${fmtT(p.FC && p.FC.bags)}`);
    if (mags.length) tPush('SECCIÓN 2', 'Producto', `Producto ${p.grade}: cantidades difieren entre documentos.`, mags.join(' · ') + ' → verificar.');
  }
  // Contenedores (filas REVISAR + lista)
  for (const r of eq.rows) {
    if (r.estado !== 'REVISAR') continue;
    const difs = [];
    if (/Seal BL≠Aduana/.test(r.notas)) difs.push(`Precinto BL ${r.seal.BL || '—'} ≠ Aduana ${r.seal.Aduana || '—'}`);
    if (/Net difiere/.test(r.notas)) difs.push(`Neto BL ${fmtT(r.net.BL)} / Aduana ${fmtT(r.net.Aduana)} / Booking ${fmtT(r.net.Booking)} kg`);
    if (/Gross difiere/.test(r.notas)) difs.push(`Bruto BL ${fmtT(r.gross.BL)} / Aduana ${fmtT(r.gross.Aduana)} / Booking ${fmtT(r.gross.Booking)} kg`);
    if (/Measurement difiere/.test(r.notas)) difs.push(`Vol BL ${r.meas.BL_m3} m³ ≠ Booking ${r.meas.BA_m3} m³`);
    if (/Wooden/.test(r.notas)) difs.push(`Wooden BL: ${r.wooden.BL || 'sin tratamiento declarado'}`);
    if (/No figura/.test(r.notas)) difs.push(r.notas);
    tPush('CONTENEDORES', r.container || r.container_aduana || '—',
      `Contenedor ${r.container || r.container_aduana}: ${r.notas}.`, (difs.join(' · ') || 'Ver tabla de contenedores') + ' → verificar.');
  }
  if (eq.meta && eq.meta.estado === 'REVISAR')
    tPush('CONTENEDORES', 'Listado', eq.meta.notas.join(' · ') + '.', 'Comparar la lista de contenedores entre los documentos.');
  // Flete
  if (fleteAviso) tPush('FLETE', 'Flete FC ↔ BL', fleteAviso + '.', 'Revisar la tabla de tarifa (TOTAL USD / tarifa por contenedor).');
  // Documentos: faltantes/degradados + warns accionables (D4) — sin duplicar lo ya derivado
  for (const m of missing_docs) tPush('DOCUMENTOS', m.doc, m.motivo + '.', 'Verificar el documento o reintentar la corrida.');
  for (const a of proactive_comments) {
    if (a.level !== 'warn') continue;
    if (fleteAviso && a.text === fleteAviso) continue;                      // ya está en FLETE
    if (/nombre difiere|sin contraparte en/.test(a.text)) continue;         // ya derivado por fila
    tPush(/Núcleo|Producto /.test(a.text) ? 'SECCIÓN 2' : 'DOCUMENTOS', a.doc, a.text, '');
  }
  const triage = [].concat(buckets['SECCIÓN 1'], buckets['SECCIÓN 2'], buckets['CONTENEDORES'], buckets['FLETE'], buckets['DOCUMENTOS']);
  const header_resumen = {
    revisar: triage.length, ok: counters.OK, counters_revisar: counters.REVISAR,
    booking: bookingBL || bookingBA || '', vessel: vesselBL, of_kind: ofKind || '',
  };

  /* ================= RESUMEN ESTRUCTURADO (sin consumidores conocidos; se conserva) ===== */
  const compare_summary = {
    key_fields: {
      order_number: { BL: orderBL || '', BA: orderBA || '', Aduana: orderAD || '' },
      booking_no: { BL: bookingBL || '', BA: bookingBA || '' },
      bl_number: bl.bl_no || '',
      pol: { BL: bl.pol || '', BA: ba.pol || '' },
      pod: { BL: bl.pod || '', BA: ba.pod || '' },
      destino: { Aduana: aduPais || '', BA: baPais || '' },
      consignee: { BL: blConsignee, BA: baConsigneeBlock },
      notify: { BL: blNotify, BA: baNotifyBlock },
      consignee_tax: { BL: taxBL, BA: taxBA },
      pe: { BL: blPE, Aduana: aduPE },
      totals: {
        BL: { bultos: String(bolsasBL || palletsBL || ''), net: (bl.desc && bl.desc['DESC BL - PESO NETO TOTAL (KG)']) || '', gross: (bl.desc && bl.desc['DESC BL - PESO BRUTO TOTAL (KG)']) || '' },
        Aduana: { bultos: (adu.totals && adu.totals.bultos) ?? '', net: (adu.totals && adu.totals.neto) ?? '', gross: (adu.totals && adu.totals.bruto) ?? '' },
        BA: { bultos: (ba.totales && ba.totales.piece_count) ?? '', net: (ba.totales && ba.totales.net_kg) ?? '', gross: (ba.totales && ba.totales.gross_kg) ?? '' },
      },
    },
    overall: counters.REVISAR > 0 ? 'REVISAR' : 'OK',
  };

  const compare = {
    overall: counters.REVISAR > 0 ? 'REVISAR' : 'OK',
    counters: { OK: counters.OK, REVISAR: counters.REVISAR },
    notes: counters.REVISAR > 0 ? 'Existen diferencias para revisar (ver ítems Estado=REVISAR).' : 'Sin diferencias relevantes.',
  };

  return { compare_bl_anchored: { campos, totales }, compare_summary,
           compare_equipos: eq.rows, compare_equipos_meta: eq.meta,
           compare_equipos_resumen: eq.resumen, compare,
           compare_productos: prod.rows, compare_productos_summary,
           triage, header_resumen,
           header_badges, proactive_comments, missing_docs, is_bulk: isBulk };
}

/* =========================
   n8n Code node (Run Once for Each Item)
   ========================= */
const current = $input.item;
const doc = current.json || current;
const result = buildComparison(doc);
return { json: { ...doc, ...result } };

/**
 * NODO Code post-IA — "Inyectar pe + source_link"
 * Modo: Run Once for Each Item  ·  Lenguaje: JavaScript
 * onError: continueRegularOutput  (D2 = continue-on-fail con log explícito)
 *
 * Va ENTRE el "Parser Aduana (IA)" (Basic LLM Chain) y "Set Aduana: Join Key".
 *
 * Por qué existe (verificado contra el regex actual y el HTML del mail):
 *  - El chainLlm v1.9 NO preserva el input → se pierden los campos de Drive y los
 *    de la normalización (order_number, orden_from_name, webViewLink, fileId, ...).
 *    El regex hacía `return { json: { ...j, aduana_extract, ... } }` (spread del input).
 *    Acá restauramos ese passthrough leyendo del upstream real.
 *  - outputParserStructured envuelve la salida en una clave "output".
 *  - El HTML del mail (nodo intocable) lee adu.pe (L173) y adu.source_link (L136),
 *    que el LLM NO puede producir desde el texto:
 *      · pe         = alias de ddt           (regex L308: pe: ddt || null)
 *      · source_link = link de Drive del input (regex L298/L313 via pickDriveLink)
 */

// pickDriveLink — copia EXACTA de la lógica del regex (Parser Aduana (Code) L228-238)
function pickDriveLink(j) {
  const cands = [];
  if (j.webViewLink) cands.push(j.webViewLink);
  if (j.links && j.links.webViewLink) cands.push(j.links.webViewLink);
  if (j.aduana_webViewLink) cands.push(j.aduana_webViewLink);
  if (j.aduana_links && j.aduana_links.webViewLink) cands.push(j.aduana_links.webViewLink);
  if (cands.length > 0) return cands[0];

  const fileId = j.fileId || (j.links && j.links.fileId) || (j.aduana_links && j.aduana_links.fileId);
  if (fileId) return `https://drive.google.com/file/d/${fileId}/view?usp=drivesdk`;
  return "";
}

// Input que el chainLlm descartó = mismo origen que leía el regex (j = su input).
// El nodo inmediatamente anterior al parser era "PDF — Extract From PDF (Aduana)".
let up = {};
try {
  up = $('PDF — Extract From PDF (Aduana)').item.json || {};
} catch (e) {
  // Si se rompe el pairing de items a través del chain, degradamos sin romper.
  console.log('[Inyectar pe + source_link] no se pudo leer upstream PDF Aduana:', e.message);
  up = {};
}

// Salida del LLM chain. outputParserStructured envuelve en "output";
// el schema raíz es { aduana_extract: {...} }. Desenvolvemos defensivamente ambos niveles.
const root = ($json && $json.output) ? $json.output : $json;
let adu = (root && root.aduana_extract) ? root.aduana_extract : root;

// D2 — continue-on-fail: si el parser IA no produjo un objeto válido, log + passthrough
// sin romper. Set Aduana: Join Key usa optional chaining, soporta aduana_extract = null.
if (!adu || typeof adu !== 'object' || Array.isArray(adu)) {
  console.log('[Inyectar pe + source_link] aduana_extract ausente/inválido — continue-on-fail. $json:',
    JSON.stringify($json).slice(0, 500));
  return { json: { ...up, aduana_extract: null } };
}

/* ---------------------------------------------------------------------------
 * Clasificación ORDEN vs PERMISO por ESTRUCTURA (no por rótulo).
 * El confeccionador puede rotular mal: poner el PERMISO bajo "OPERACIÓN:" y dejar
 * la ORDEN suelta en el body. El joinKey debe ser SIEMPRE la orden (sino el Merge
 * queda vacío y el flujo se corta en silencio). Dominio (confirmado por John):
 *   - ORDEN  : empieza con 1 o 4, 9-10 dígitos (118639311, 4010564469).
 *              El shipment SAP (ej. 46674302, 8 díg) NO colisiona.
 *   - PERMISO: \d{5}EC\d{8} + letra de control opcional (26033EC01003834L).
 * La planilla SIEMPRE se nombra con la orden → el filename es la fuente confiable.
 * ------------------------------------------------------------------------- */
const isOrden   = (digits) => /^[14]\d{8,9}$/.test(String(digits || ''));
const PERMISO_RE = /\b\d{5}EC\d{8}[A-Z]?\b/i;
const isPermiso = (s) => /^\d{5}EC\d{8}[A-Z]?$/i.test(String(s || '').trim());
const firstOrdenToken = (str) => (String(str || '').match(/[14]\d{8,9}/g) || []).find(isOrden) || '';

// PE/DDT: si "OPERACIÓN:" trajo el PERMISO y ddt quedó vacío, poblá ddt con el permiso
// (raw del body, con letra de control) para que el display del PE de Aduana no quede vacío.
if (!adu.ddt) {
  const permRaw = (PERMISO_RE.exec(String(up.text || '')) || [])[0]
    || (isPermiso(adu.operacion) ? adu.operacion : '');
  if (permRaw) adu.ddt = String(permRaw).toUpperCase();
}

// Resolver la ORDEN: filename (confiable) → operacion-si-orden → token único del body.
const baseName = String(up.name || '').replace(/\.[A-Za-z0-9]+$/, '');
const opDigits = String(adu.operacion || '').replace(/\D/g, '');
// FIX falso multi-orden (Tanda C.1): la celda "CONTENEDORES CONSOLIDADOS POR SOLICITUD
// PARTICULAR: 1565-1633-35/26" trae números de TRÁMITE del despachante que, linearizados sin
// guiones por la extracción del PDF, pasan isOrden (10 dígitos arrancando en 1) → falso
// orden_multi → falso REVISAR en el (6). Se excluye SOLO esa línea y sus continuaciones
// INMEDIATAS de solo dígitos/puntuación (wrap del trámite). Anclado estricto: una línea
// solo-dígitos en cualquier otro contexto (p.ej. arrastre de una 2ª orden real) se CONSERVA
// y sigue disparando orden_multi → REVISAR.
const bodyLines = String(up.text || '').split('\n');
const bodyKeep = [];
for (let li = 0; li < bodyLines.length; li++) {
  if (/SOLICITUD\s+PARTICULAR/i.test(bodyLines[li])) {
    while (li + 1 < bodyLines.length && bodyLines[li + 1].trim() && /^[\d\s.,\/-]+$/.test(bodyLines[li + 1])) li++;
    continue;
  }
  bodyKeep.push(bodyLines[li]);
}
const bodyOrders = [...new Set(bodyKeep.join('\n').split(/[^0-9A-Za-z]+/).filter(isOrden))];
let orden =
  firstOrdenToken(baseName) ||
  ((isOrden(opDigits) && !isPermiso(adu.operacion)) ? opDigits : '') ||
  (bodyOrders.length === 1 ? bodyOrders[0] : '') ||
  '';
adu.orden = orden ? orden.replace(/\D/g, '').replace(/^0+/, '') : null;

// Multi-orden (raro, marítimo): NO elegir en silencio → flag visible (lo surface el comparador).
adu.orden_multi = bodyOrders.length > 1;
adu.orden_candidatos = bodyOrders;

// Inyectar lo que el LLM no puede sacar del texto:
adu.pe = adu.ddt || null;                        // alias explícito (regex L308)
adu.source_link = pickDriveLink(up) || null;     // link de Drive (regex L298/L313)

// BUG5: grado derivado del nombre de producto de aduana ("LDPE 230N" -> "230N"; "DOWLEX TG2085B" -> "TG2085B").
// Primer token alfanumérico que contiene un dígito. Doc-level (desde el primer contenedor).
function gradeFromProduct(p) {
  const toks = String(p || '').toUpperCase().match(/\b[A-Z0-9]*\d[A-Z0-9]*\b/g) || [];
  return toks.find((t) => /[0-9]/.test(t)) || '';
}
// FIX3: limpiar producto que absorbió tokens vecinos (buque pegado o peso "KG27.540,00").
// Corte estructural: remueve adu.buque si quedó pegado y corta la basura desde la unidad "KG".
// Display only — no afecta operacion/orden/joinKey/grado (que sale del primer token con dígito).
function cleanProducto(p, buque) {
  let s = String(p || '').replace(/\s+/g, ' ').trim();
  if (!s) return s;
  if (buque) {
    const b = String(buque).trim();
    if (b) s = s.replace(new RegExp('\\s*' + b.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '.*$', 'i'), '').trim();
  }
  s = s.replace(/\s*\bKG\s*[\d.,].*$/i, '').trim();   // "KG27.540,00" / "KG 27.540"
  s = s.replace(/\s*\bKG\b.*$/i, '').trim();           // "KG LOG-IN RESILIENTE 495"
  return s;
}
if (Array.isArray(adu.contenedores)) {
  for (const c of adu.contenedores) {
    if (c && c.producto != null) c.producto = cleanProducto(c.producto, adu.buque);
  }
}

const aduProd = (Array.isArray(adu.contenedores) && adu.contenedores[0] && adu.contenedores[0].producto) || '';
adu.grado = gradeFromProduct(aduProd);

// PUT-5c: BULTOS por contenedor desde el raw de la planilla (el LLM no los extrae por contenedor; solo el total).
// La fila es "<TP> <CONTAINER> <PRECINTO> <PRODUCTO...> <BULTOS> <NETO> <BRUTO>". Tomamos los 3 enteros "puros"
// (no pegados a letras) del segmento de cada contenedor; bultos = el que precede a neto/bruto (que ya están extraídos).
// "bultos" = en carga paletizada equivale a pallets; granel/suelta no paletizada es edge (no bloquea).
function parseBultosAduana(txt, conts) {
  if (!Array.isArray(conts) || !conts.length) return;
  const norm = String(txt || '').replace(/\r/g, ' ').replace(/\n/g, ' ').replace(/\s+/g, ' ');
  const U = norm.toUpperCase();
  for (let i = 0; i < conts.length; i++) {
    const c = conts[i];
    const code = String(c.container || '').toUpperCase();
    if (!code) continue;
    const idx = U.indexOf(code);
    if (idx < 0) continue;
    let end = norm.length;
    for (let j = 0; j < conts.length; j++) {
      if (j === i) continue;
      const oc = String(conts[j].container || '').toUpperCase();
      const oi = oc ? U.indexOf(oc, idx + code.length) : -1;
      if (oi > idx && oi < end) end = oi;
    }
    const seg = norm.slice(idx + code.length, end);
    const ints = (seg.match(/(?<![\w.,])\d{1,9}(?![\w])/g) || []).map((s) => Number(s));
    const neto = Math.round(Number(c.neto)); const bruto = Math.round(Number(c.bruto));
    let bultos = null;
    for (let k = 0; k + 2 < ints.length + 1; k++) {
      if (ints[k + 1] === neto && ints[k + 2] === bruto) { bultos = ints[k]; break; }
    }
    if (bultos == null && ints.length >= 3) bultos = ints[0]; // fallback posicional
    if (bultos != null) c.bultos = bultos;
  }
}
parseBultosAduana(up.text, adu.contenedores);

// Restaurar el passthrough del input (paridad con `...j` del regex) + aduana_extract.
return { json: { ...up, aduana_extract: adu } };

/**
 * NODO Code post-IA — "Inyectar links + order (Booking)"
 * Modo: Run Once for Each Item  ·  Lenguaje: JavaScript
 * onError: continueRegularOutput  (D2 = continue-on-fail con log explícito)
 *
 * Va ENTRE el "Parser Booking (IA)" (Basic LLM Chain) y "Set Booking: Join Key".
 *
 * Por qué existe (verificado contra el regex actual y los consumers COMPARADOR/HTML):
 *  - El chainLlm NO preserva el input → se pierden los campos de Drive y el text del
 *    upstream. El regex hacía `return { json: { ...input, booking_extract, ... } }`.
 *    Acá restauramos ese passthrough leyendo del upstream real ("PDF → Texto (Booking)").
 *  - outputParserStructured envuelve la salida en una clave "output".
 *  - Campos que el LLM NO puede producir desde el texto del PDF:
 *      · links.webViewLink = link de Drive del input (regex: links.webViewLink)
 *      · order_number determinístico = token de 9-10 dígitos del FILENAME (la orden);
 *        el shipment (8 dígitos) se descarta por LARGO. Fallback: IA → upstream.
 *      · ncm_export = alias/mirror de hs.export (regex: ncm_export = hs_export)
 */

function pickDriveLink(j) {
  if (j.webViewLink) return j.webViewLink;
  if (j.links && j.links.webViewLink) return j.links.webViewLink;
  const fid = j.id || j.fileId || (j.links && j.links.fileId);
  return fid ? `https://drive.google.com/file/d/${fid}/view?usp=drivesdk` : "";
}
function digitsOnly(s) { return String(s || "").replace(/[^\d]/g, ""); }
function orderFromName(name) {
  // Tanda A: filename BA = "<shipment(8d)>_<orden(9-10d)>_ZCB3_BA.pdf".
  // La orden se elige por LARGO (9 o 10 dígitos), no por posición; el shipment (8d) nunca matchea.
  const toks = String(name || "").match(/\d+/g) || [];
  return toks.find((t) => t.length === 9 || t.length === 10) || "";
}

// Input que el chainLlm descartó = output de "PDF → Texto (Booking)" (mismo que leía el regex).
let up = {};
try {
  up = $('PDF → Texto (Booking)').item.json || {};
} catch (e) {
  console.log('[Inyectar Booking] no se pudo leer upstream PDF Booking:', e.message);
  up = {};
}

// Salida del LLM: outputParserStructured envuelve en "output"; raíz { booking_extract }.
const root = ($json && $json.output) ? $json.output : $json;
let ba = (root && root.booking_extract) ? root.booking_extract : root;

// D2 — continue-on-fail: si el parser IA no produjo objeto válido, log + passthrough sin romper.
// Set Booking: Join Key usa optional chaining ($json.booking_extract?.order_number), soporta null.
if (!ba || typeof ba !== 'object' || Array.isArray(ba)) {
  console.log('[Inyectar Booking] booking_extract ausente/inválido — continue-on-fail. $json:',
    JSON.stringify($json).slice(0, 500));
  return { json: { ...up, booking_extract: null } };
}

// Tanda A: order_number determinístico — del FILENAME (token 9-10 dígitos), fallback IA → upstream.
const stripZeros = (s) => String(s || "").replace(/^0+/, "");
const fileOrder = orderFromName(up.name);
const iaOrder   = digitsOnly(ba.order_number);
const upOrder   = digitsOnly(up.order_number || up.orden_from_name || "");
ba.order_number = fileOrder || iaOrder || upOrder || "";

// Cross-check filename vs IA: si la IA extrajo orden (no hubo 429) y difiere del filename,
// se flaggea — buildGuard (COMPARADOR) lo baja a missing_docs. IA caída → vale filename, sin flag.
if (fileOrder && iaOrder && stripZeros(fileOrder) !== stripZeros(iaOrder)) {
  ba.order_mismatch = { file: fileOrder, ia: iaOrder };
}

// links de Drive (el LLM no los ve en el texto) — el HTML del mail lee links.webViewLink.
ba.links = {
  webViewLink: pickDriveLink(up) || "",
  fileId: up.id || (up.links && up.links.fileId) || "",
  name: up.name || "",
};

// ncm_export = mirror de hs.export (alias derivado; el COMPARADOR lee ba.ncm_export).
ba.ncm_export = (ba.hs && ba.hs.export) ? ba.hs.export : "";

// ===== BUG2: booking_no = el de fecha MÁXIMA en "External Carrier Notes" (rebooking) =====
// Patrón real: "<Mmm> <DD> <YYYY>\nBOOKING NUMBER:<XXX>". Tomamos el de fecha más nueva.
const MONTHS = { jan:1, feb:2, mar:3, apr:4, may:5, jun:6, jul:7, aug:8, sep:9, oct:10, nov:11, dec:12 };
function latestBookingFromNotes(txt) {
  const re = /([A-Za-z]{3,9})\s+(\d{1,2})\s+(\d{4})\s+BOOKING\s*NUMBER\s*:\s*([A-Z0-9]+)/gi;
  let m, best = null, bestKey = -1;
  while ((m = re.exec(String(txt || ''))) !== null) {
    const mo = MONTHS[m[1].slice(0, 3).toLowerCase()];
    if (!mo) continue;
    const key = (+m[3]) * 10000 + mo * 100 + (+m[2]);
    if (key > bestKey) { bestKey = key; best = m[4]; }
  }
  return best;
}
const latestBk = latestBookingFromNotes(up.text);
if (latestBk) ba.booking_no = latestBk;

// ===== VOLUME por contenedor (Item Volume CD3, formato US) — para el comparador (measurement) =====
const parseUS = (s) => { const n = Number(String(s).replace(/,/g, '')); return Number.isFinite(n) ? n : null; };
if (Array.isArray(ba.equipos) && up.text) {
  const txt = up.text;
  const idxs = ba.equipos
    .map((e) => ({ e, i: e.container ? txt.indexOf(e.container) : -1 }))
    .filter((o) => o.i >= 0).sort((a, b) => a.i - b.i);
  for (let k = 0; k < idxs.length; k++) {
    let seg = txt.slice(idxs[k].i, k + 1 < idxs.length ? idxs[k + 1].i : txt.length);
    // Tanda C.1: el último segmento se recorta en los totales del doc (evita que "Total Volume"
    // y el bloque de totales se cuelen en el volumen/contenido del último contenedor).
    const cutTot = seg.search(/Total Gross weight/i);
    if (cutTot > 0) seg = seg.slice(0, cutTot);
    const mv = seg.match(/Item Volume\s*:\s*([\d.,]+)\s*CD3/i);
    if (mv) idxs[k].e.volume_cd3 = parseUS(mv[1]);
    else {
      // Tanda C.1 — FIX Vol BA: la linearización del PDF puede DESPLAZAR el valor de
      // "Item Volume :" (queda p.ej. "1,080 BAG /…" pegado al label). El bloque secundario
      // del MISMO segmento trae "Volume 45,522.000 CD3" → fallback. El lookbehind excluye
      // "Total Volume". Verificado contra el raw real de exec 27741 (FFAU3921953).
      const mv2 = seg.match(/(?<!Total\s)\bVolume\s+([\d.,]+)\s*CD3/i);
      if (mv2) idxs[k].e.volume_cd3 = parseUS(mv2[1]);
    }
    // Tanda C.1 — CONTENIDO por contenedor (producto · bolsas · pallets) para el mail v10.
    // Pares (bolsas, producto) por orden de aparición dentro del segmento; un contenedor con
    // 2+ productos produce 2+ entradas (la plantilla las apila). pallets = bolsas / bpp.
    const bagsList = [...seg.matchAll(/([\d,]+)\s*BAG\s*\//g)].map((m) => parseUS(m[1]));
    const prodList = [...seg.matchAll(/\b\d{11}\s+(.{5,80}?)\s+\d+\s*KG\s+B/g)]
      .map((m) => m[1].replace(/[™®]/g, '').replace(/^[:\s]+/, '').trim());
    const bppSeg = parseUS((seg.match(/(\d+)\s*Bags on a Pallet/i) || [])[1]);
    const contenido = [];
    for (let p = 0; p < Math.max(bagsList.length, prodList.length); p++) {
      const bolsas = (bagsList[p] != null) ? bagsList[p] : null;
      contenido.push({ producto: prodList[p] || '', bolsas,
        pallets: (bolsas != null && bppSeg) ? Math.round(bolsas / bppSeg) : null });
    }
    if (contenido.length) idxs[k].e.contenido = contenido;
  }
}

// ===== Tanda C.1 — (10A) ORIGINALS: release point desde el RAW del BA (regex, SIN IA) =====
// 4 variantes reales relevadas sobre 13 BAs (2026-06-05): (A) "RELEASE BILL OF LADING AT
// DESTINATION [PORT]", (B) "Originals Released at the Destination", (C) "B/L Release Point
// Destination" (sección 13C), (D) "#13C# Release Point ↵ Destination release".
// Anti falsos positivos verificado: "CUTOFF AT ORIGIN", "Country of Origin" y "release of
// the hopper car" no matchean ninguna. Valores mixtos entre variantes → conflict (REVISAR).
function originalsFromBA(rawText) {
  const t = String(rawText || '');
  const found = [];
  const RES = [
    /RELEASE\s+BILL\s+OF\s+LADING\s+AT\s+(DESTINATION|ORIGIN)\b/gi,
    /ORIGINALS?\s+RELEASED?\s+AT\s+THE\s+(DESTINATION|ORIGIN)\b/gi,
    /B\/?L\s+Release\s+Point\s+(Destination|Origin)\b/gi,
    /Release\s+Point\s*\n\s*(Destination|Origin)\s+release/gi,
  ];
  for (const re of RES) { let m; while ((m = re.exec(t)) !== null) found.push(m[1].toUpperCase()); }
  const vals = [...new Set(found.map((v) => (v === 'DESTINATION' ? 'DESTINO' : 'ORIGEN')))];
  if (!vals.length) return { value: '', conflict: false, matches: 0 };
  if (vals.length > 1) return { value: '', conflict: true, matches: found.length };
  return { value: vals[0], conflict: false, matches: found.length };
}
ba.originals_release = originalsFromBA(up.text);

// ===== WOODEN del BA (doc-level): "Wooden Package [used] : <tratamiento>" =====
// Prioridad: Treated/Certified > Processed/Heat > primer valor no "Not applicable".
function woodenFromBA(txt) {
  const re = /Wooden Package(?:\s+used)?\s*:\s*([^\n]+)/gi;
  let m; const vals = [];
  while ((m = re.exec(String(txt || ''))) !== null) vals.push(m[1].trim());
  if (!vals.length) return '';
  return vals.find((v) => /treated|certified/i.test(v))
    || vals.find((v) => /processed|heat/i.test(v))
    || vals.find((v) => !/not applicable|not used/i.test(v))
    || vals[vals.length - 1];
}
ba.wooden_package = woodenFromBA(up.text);

// ===== NOTIFY desde instrucciones del BA (#5) — DETECTA y MUESTRA, no auto-resuelve =====
// Compara lo que el BA DICE que debe ir de notify (campo estructurado + instrucción de texto)
// para que el COMPARADOR lo cruce contra el BL. NO pisa el estructurado: John valida.
function buildNotifyMeta(rawText, baObj) {
  const _digits = (s) => String(s == null ? '' : s).replace(/\D+/g, '');
  const _n14 = (s) => { const d = _digits(s); return d.length > 14 ? d.slice(-14) : d; };
  const _lc = (s) => String(s || '').trim().toLowerCase();
  const _uniq = (a) => [...new Set(a.filter(Boolean))];

  const txt = String(rawText || '');
  const notify = (baObj && baObj.notify) || {};
  const structuredNotifyCnpj  = _n14(notify.tax_id || '');
  const structuredNotifyEmail = _lc(notify.email || '');
  const notify_structured = { name: notify.name || '', cnpj: structuredNotifyCnpj || '', email: structuredNotifyEmail || '' };

  // sold_to / ship_to (header futuro + set de exclusión). Best-effort sobre el raw garbleado.
  const allCustTax = (txt.match(/Customer Tax ID Number\s+(\d{11,14})/ig) || [])
    .map(s => _n14((/(\d{11,14})/.exec(s) || [])[1] || ''));
  const sold_to = { tax: allCustTax[0] || '', raw_present: /Sold-to/i.test(txt) };
  const ship_to = { tax: allCustTax[1] || allCustTax[0] || '', raw_present: /Ship-to/i.test(txt) };

  // Ventana de instrucciones: anclar en keyword (NO la sola palabra "NOTIFY"); ventana LOCAL por keyword.
  const KW = /(?:please\s+also\s+mention|also\s+mention|mention\s*:?\s*also|\bNOTIFY\s*:)/ig;
  let m, idxs = []; while ((m = KW.exec(txt)) !== null) idxs.push(m.index);
  const keywordPresent = idxs.length > 0;

  let windowEmails = [], windowCnpjs = [];
  if (keywordPresent) {
    const emails = [], cnpjs = [];
    for (const idx of idxs) {
      const win = txt.slice(Math.max(0, idx - 350), Math.min(txt.length, idx + 450));
      emails.push(...(win.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig) || []).map(_lc));
      cnpjs.push(...(win.match(/\b\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}\b/g) || []).map(_n14));
    }
    windowEmails = _uniq(emails); windowCnpjs = _uniq(cnpjs);
  }

  // Set de exclusión = CNPJs de consignee/sold/ship (estructurado + raw).
  const exclusion = new Set([ _n14((baObj && baObj.consignee && baObj.consignee.tax_id) || ''),
    sold_to.tax, ship_to.tax, ...allCustTax ].filter(Boolean));

  // CNPJ que (a) está en ventana NOTIFY y (b) NO es consignee/sold/ship.
  const filteredNotifyCnpjs = windowCnpjs.filter(c => !exclusion.has(c));
  const notifyEmailsInfo = windowEmails.filter(e => !/@dow\.com$/i.test(e)); // quita dominio shipper
  const preferredEmail = (structuredNotifyEmail && windowEmails.includes(structuredNotifyEmail))
    ? structuredNotifyEmail : (notifyEmailsInfo[0] || '');

  // Co-presencia: email O CNPJ válido en la ventana (anti falso positivo "NOTIFY" suelto).
  const has_text_instructions = keywordPresent && (windowEmails.length > 0 || windowCnpjs.length > 0);
  const structuredMatches = structuredNotifyCnpj && filteredNotifyCnpjs.includes(structuredNotifyCnpj);
  const hasStructured = !!(structuredNotifyCnpj || structuredNotifyEmail || notify.name);

  // Flags POST-exclusión (decisión cerrada: notifies reales, no CNPJs crudos).
  const notify_differ = has_text_instructions && filteredNotifyCnpjs.length > 0 && !structuredMatches;
  const notify_multiple = has_text_instructions && (
    filteredNotifyCnpjs.length >= 2 ||
    (hasStructured && filteredNotifyCnpjs.length >= 1 && !structuredMatches));

  // notify_instruction[] (candidatos; nombre/email best-effort, NO comparables; el veredicto va por CNPJ).
  const notify_instruction = filteredNotifyCnpjs.length
    ? filteredNotifyCnpjs.map((cnpj) => ({ cnpj, email: preferredEmail, name: '' }))
    : notifyEmailsInfo.map((email) => ({ cnpj: '', email, name: '' }));

  return { notify_structured, notify_instruction,
    notify_emails_window: windowEmails, notify_cnpjs_kept: filteredNotifyCnpjs,
    notify_cnpjs_excluded: windowCnpjs.filter(c => exclusion.has(c)),
    has_text_instructions, notify_multiple, notify_differ, sold_to, ship_to };
}
ba.notify_meta = buildNotifyMeta(up.text, ba);

// PUT-5d: "N Bags on a Pallet" del raw del Booking → para derivar pallets (pallets = piece_count / N) en el mail.
// El Booking no declara pallets explícitos; sí trae "60 Bags on a Pallet". Captura raw (sin tocar prompt).
const _bpp = (String(up.text || '').match(/(\d+)\s*Bags on a Pallet/i) || [])[1];
if (_bpp) ba.bags_per_pallet = Number(_bpp);

// Tanda BULK — Piece Count unit: "Piece Count : 1.080,000 BAG" / "4,320.000 BAG" / "126,420.000 KG"
// Se inyecta POST-IA sobre el raw del BA (sin tocar prompt ni schema). El COMPARADOR usa este campo
// para distinguir bulk (KG) de containerizado (BAG) sin leer ningún campo no estructurado.
// Guard: null si ba.totales no existe (no hay a dónde escribir) o si el raw no matchea.
if (ba.totales) {
  const _pcMatch = String(up.text || '').match(/Piece\s*Count\s*:\s*[\d.,]+\s*([A-Z]{2,3})\b/i);
  ba.totales.piece_count_unit = _pcMatch ? _pcMatch[1].toUpperCase() : null;
}

// Restaurar el passthrough del input (paridad con `...input` del regex) + booking_extract.
return { json: { ...up, booking_extract: ba } };

/**
 * NODO Code post-IA — "Inyectar metadata (LOG-IN)"
 * Modo: Run Once for Each Item · JavaScript · onError: continueRegularOutput
 * Va ENTRE "Parser LOG-IN (IA)" (chainLlm) y el fan-out (Buscar Aduana / Buscar Booking / Set BL Join Key).
 *
 * Responsabilidades:
 *  1. Passthrough del input que el chainLlm descarta (text, order_number, booking_no, webViewLink),
 *     leído del upstream directo "Switch ...". (paridad con `...input` del regex).
 *  2. FREIGHT: clasifica PREPAID/COLLECT por reconciliación de balance contra los totales
 *     (porta parseFreightByColumns del regex). Calcula per_container y ocean_freight_kind.
 *  3. TRADUCTOR: snake_case del LLM → keys verbatim "DESC BL - ..." que consume COMPARADOR/HTML.
 *  4. Totales desc = suma de items (aritmética determinística en Code, no en LLM).
 *  5. UPPERCASE de los campos que el regex subía con upperKeepNL.
 *  6. Emite login_extract con el contrato exacto (§4 handoff) + campos nuevos (originals_to_be_released_at, type_of_move) en root.
 */

const UP_NODE = 'Switch (ruteo por naviera + validación de orden)';

function up(s) { return (s == null ? '' : String(s)).toUpperCase(); }
function num(x) { if (x == null) return null; const n = Number(x); return Number.isFinite(n) ? n : null; }
function digits(s) { return String(s || '').replace(/[^\d]/g, ''); }
function round2(x) { return Math.round((Number(x) || 0) * 100) / 100; }
function cur3(s) { return up(s) === 'BRL' ? 'BRL' : 'USD'; }
// PUT-1 (tanda Factura/productos): token de grade desde la descripción del producto.
// Copia EXACTA de inj_aduana ("Inyectar pe + source_link") — clave de match cross-doc
// (35057L/35060L/230N). Primer token alfanumérico que contiene un dígito.
function gradeFromProduct(p) {
  const toks = String(p || '').toUpperCase().match(/\b[A-Z0-9]*\d[A-Z0-9]*\b/g) || [];
  return toks.find((t) => /[0-9]/.test(t)) || '';
}

// ---- upstream passthrough (lo que el chainLlm descartó) ----
let u = {};
try { u = $(UP_NODE).item.json || {}; }
catch (e) { console.log('[Inyectar LOG-IN] upstream no leído:', e.message); u = {}; }

// ---- salida del LLM: outputParserStructured envuelve en "output"; raíz { login_extract } ----
const root = ($json && $json.output) ? $json.output : $json;
let x = (root && root.login_extract) ? root.login_extract : root;

// continue-on-fail: si el parser IA no produjo objeto válido, log + passthrough sin romper.
if (!x || typeof x !== 'object' || Array.isArray(x)) {
  console.log('[Inyectar LOG-IN] login_extract ausente/inválido — continue-on-fail. $json:',
    JSON.stringify($json).slice(0, 500));
  return { json: { ...u, login_extract: null } };
}

const d = x.description || {};

// ===== FREIGHT — reconciliación (porta parseFreightByColumns) =====
const fl = x.freight_lines || {};
const rawConcepts = Array.isArray(fl.concepts) ? fl.concepts : [];
const rawTotals = Array.isArray(fl.totals_lines) ? fl.totals_lines : [];

const totals = { USD: { prepaid: 0, collect: 0 }, BRL: { prepaid: 0, collect: 0 } };
for (const t of rawTotals) {
  const c = cur3(t.currency);
  totals[c].prepaid = num(t.prepaid_amount) || 0;
  totals[c].collect = num(t.collect_amount) || 0;
}

const concepts = [...rawConcepts].sort((a, b) => (num(a.line_number) ?? 0) - (num(b.line_number) ?? 0));
const rem = {
  USD: { prepaid: totals.USD.prepaid, collect: totals.USD.collect },
  BRL: { prepaid: totals.BRL.prepaid, collect: totals.BRL.collect },
};
const outConcepts = [];
for (const c of concepts) {
  const cu = cur3(c.currency);
  const amt = num(c.amount);
  let kind = null;
  if (amt != null) {
    const canPre = amt <= (rem[cu]?.prepaid ?? 0);
    const canCol = amt <= (rem[cu]?.collect ?? 0);
    if (canPre && (!canCol || amt === (rem[cu]?.prepaid ?? 0))) {
      kind = 'PREPAID'; rem[cu].prepaid -= amt;
    } else if (canCol) {
      kind = 'COLLECT'; rem[cu].collect -= amt;
    } else {
      const col = (c.column || '').toLowerCase();
      if (col === 'left') kind = 'PREPAID';
      else if (col === 'right') kind = 'COLLECT';
      else kind = /ORIGEM/i.test(c.concept || '') ? 'PREPAID' : 'COLLECT';
    }
  }
  outConcepts.push({
    concept: c.concept || '',
    kind,
    currency: cu,
    amount: amt,
    rate_currency: cur3(c.rate_currency),
    rate: num(c.rate),
  });
}

let oceanFreightKind = '';
for (const c of outConcepts) {
  const name = up(c.concept);
  if (name.includes('OCEAN') && name.includes('FREIGHT') && (c.kind === 'PREPAID' || c.kind === 'COLLECT')) {
    oceanFreightKind = c.kind; break;
  }
}

// ===== DESC totals = suma de items (con regex residual BUG6 sobre el texto crudo) =====
const items = Array.isArray(d.items) ? d.items : [];
const hasItems = items.length > 0;
const sumItems = (f) => items.reduce((s, it) => s + (num(it[f]) || 0), 0);

// BUG6: bolsas/pallets desde el patrón "{X} BAGS IN {Y} PALLETS" del texto crudo (regex residual, PRIMARIO).
// Suma todas las ocurrencias (multi-ítem). Fallback a la suma de items[] del LLM si no matchea.
const parseCount = (s) => { const n = parseInt(String(s).replace(/[.,\s]/g, ''), 10); return Number.isFinite(n) ? n : null; };
const bagsPalletsFromText = (txt) => {
  const re = /(\d[\d.,]*)\s*BAGS?\s+IN\s+(\d[\d.,]*)\s*PALLETS?/gi;
  let m, b = 0, p = 0, hit = false;
  while ((m = re.exec(String(txt || ''))) !== null) {
    const bb = parseCount(m[1]); const pp = parseCount(m[2]);
    if (bb != null) { b += bb; hit = true; }
    if (pp != null) { p += pp; }
  }
  return hit ? { bags: b, pallets: p } : null;
};
const bpText = bagsPalletsFromText(u.text);

const bolsas = bpText ? bpText.bags : (hasItems ? sumItems('bags') : num(d.bags_total));
const pallets = bpText ? bpText.pallets : (hasItems ? sumItems('pallets') : num(d.pallets_total));
const net = hasItems ? sumItems('net_kg') : num(d.net_total_kg);
const gross = hasItems ? sumItems('gross_kg') : num(d.gross_total_kg);

const cntCont = (num(d.cantidad_contenedores) ?? 0) || (Array.isArray(x.equipos) ? x.equipos.length : 0) || 0;
let perUSDpre = 0, perUSDcol = 0;
if (cntCont > 0) {
  if (oceanFreightKind === 'PREPAID') perUSDpre = round2(totals.USD.prepaid / cntCont);
  else if (oceanFreightKind === 'COLLECT') perUSDcol = round2(totals.USD.collect / cntCont);
}
const perUSD = perUSDpre || perUSDcol || 0;

// ===== Block 3: PE, destino_pais y extras de equipos desde el raw del BL (u.text) =====
// FIX1: PE (Permiso de Embarque) por patrón en el raw (aparece tras "Wooden Condition"). Ej: 26003EC01003509H.
const peFromText = (String(u.text || '').match(/\b\d{5}EC\d{8}[A-Z]\b/) || [])[0] || '';

// PUT-5b: bloque "DESCRIPTION OF PACKAGES AND GOODS" TAL CUAL desde el raw del BL (para mostrarlo
// monoespaciado en el mail). El raw se pierde río abajo (Merge1 lo pisa con Aduana), por eso lo
// capturamos acá namespaceado en login_extract. Sin tocar prompt ni lógica de extracción.
function goodsBlockRaw(txt) {
  const t = String(txt || '');
  const hdr = /DESCRIPTION OF PACKAGES AND GOODS[^\n]*\n/i.exec(t);
  if (!hdr) return '';
  const rest = t.slice(hdr.index + hdr[0].length);
  const end = /\n\s*\(23\)\s*DECLARED VALUE|\nContainer\s+Seal\s+Type/i.exec(rest);
  return (end ? rest.slice(0, end.index) : rest).trim();
}
const goodsBlock = goodsBlockRaw(u.text);

// BUG4: destino_pais derivado del país en el consignee address ("ITAJAI - SC BRAZIL" -> BRAZIL).
function destinoFromConsignee(cons) {
  const t = up(cons);
  const map = [['BRASIL', 'BRAZIL'], ['BRAZIL', 'BRAZIL'], ['ARGENTINA', 'ARGENTINA'], ['URUGUAY', 'URUGUAY'],
    ['PARAGUAY', 'PARAGUAY'], ['CHILE', 'CHILE'], ['ESTADOS UNIDOS', 'UNITED STATES'], ['UNITED STATES', 'UNITED STATES'], ['USA', 'UNITED STATES']];
  for (const [k, v] of map) { if (t.includes(k)) return v; }
  return '';
}
const destinoPais = destinoFromConsignee(x.consignee || '');

// FIX4: CNPJ del consignee del BL (con/sin "CNPJ:"/"TAX ID:", con/sin puntos/barra/guion) → 14 dígitos.
// Evita capturar CEP (8 díg) o teléfono: prioriza etiqueta → patrón formateado → corrida de 14.
function extractCNPJ(text) {
  const t = String(text || '');
  let m = t.match(/(?:CNPJ|TAX\s*ID)\s*[:.\-]?\s*([\d][\d.\/-]{12,20})/i);
  if (m) { const dd = m[1].replace(/\D/g, ''); if (dd.length >= 14) return dd.slice(-14); }
  m = t.match(/\b\d{2}\.\d{3}\.\d{3}\/\d{4}-\d{2}\b/);
  if (m) return m[0].replace(/\D/g, '');
  m = t.match(/\b\d{14}\b/);
  if (m) return m[0];
  return '';
}
const consigneeTax = extractCNPJ(x.consignee || '');

// Measurement + Wooden por contenedor desde la tabla del raw (el LLM no los trae). Measurement queda EUROPEO crudo.
function parseEquiposExtra(text) {
  const lines = String(text || '').replace(/\r/g, '').split('\n');
  let hdr = -1;
  for (let i = 0; i < lines.length; i++) {
    if (/Container\s+Seal\s+Type\s+Tare\s+G\.?W\s+N\.?W\s+Measurement\s+Wooden\s+Material\s+Wooden\s+Conditions/i.test(lines[i])) { hdr = i; break; }
  }
  const out = {};
  if (hdr < 0) return out;
  const isTerm = (s) => !s.trim() || /^FREIGHT CHARGES/i.test(s) || /^\s*\d+\s+of\s+\d+/i.test(s);
  let i = hdr + 1;
  while (i < lines.length) {
    if (isTerm(lines[i])) break;
    const m = lines[i].match(/^\s*([A-Z]{4}\d{7})\b(.*)$/);
    if (m) {
      let row = m[1] + ' ' + m[2].trim(); let j = i + 1;
      while (j < lines.length) { const nx = lines[j]; if (/^\s*[A-Z]{4}\d{7}\b/.test(nx) || isTerm(nx)) break; row += ' ' + nx.trim(); j++; }
      const norm = row.replace(/\s+/g, ' ').trim();
      const m2 = norm.match(/^([A-Z]{4}\d{7})\s+([A-Z0-9-]+)\s+([A-Z0-9]+)\s+(\d+)\s+([0-9.,]+)\s+([0-9.,]+)\s+([0-9.,]+)\s+(Yes|No)\s+(.+)$/i);
      if (m2) out[m2[1].toUpperCase()] = { measurement: m2[7], wooden_material: m2[8], wooden_conditions: m2[9].trim() };
      i = j;
    } else i++;
  }
  return out;
}
const equiposExtra = parseEquiposExtra(u.text);

// ===== TRADUCTOR: snake_case → keys verbatim del contrato =====
const desc = {
  "DESC BL - CANTIDAD DE CONTENEDORES": num(d.cantidad_contenedores),
  "DESC BL - GOODS (DESCRIPCIÓN CRUDA)": up(d.goods_raw || ''),
  "DESC BL - PRODUCTO": up(d.producto || ''),
  "DESC BL - GRADE / CALIDAD": up(d.grade || ''),
  "DESC BL - TIPO DE EMBALAJE": up(d.embalaje || ''),
  "DESC BL - CANTIDAD DE BOLSAS": bolsas ?? null,
  "DESC BL - CANTIDAD DE PALLETS": pallets ?? null,
  "DESC BL - NCM": up(d.ncm || ''),
  "DESC BL - PESO BRUTO TOTAL (KG)": gross ?? null,
  "DESC BL - PESO NETO TOTAL (KG)": net ?? null,
  "DESC BL - PE (PERMISO DE EMBARQUE)": peFromText || up(d.pe_code || ''),
};

const equipos = (Array.isArray(x.equipos) ? x.equipos : []).map((e) => {
  const ex = equiposExtra[up(e.container || '')] || {};
  return {
    container: up(e.container || ''),
    seal: up(e.seal || ''),
    nw: num(e.net_kg),
    gw: num(e.gross_kg),
    measurement: ex.measurement || '',
    wooden_material: up(ex.wooden_material || ''),
    wooden_conditions: up(ex.wooden_conditions || ''),
  };
});

// PUT-1: productos[] por bloque GOODS (multiproducto). El LLM YA separa d.items por bloque
// (prompt regla 19, NO-SUMA); acá los PROPAGAMOS sin tocar los totales (que siguen vía bpText/suma).
// El cruce por grade (BL vs Factura vs Aduana) lo consume el COMPARADOR. Aditivo, no rompe consumers.
const products = items.map((it) => ({
  goods: up(it.goods || ''),
  grade: gradeFromProduct(it.goods || ''),
  bags: num(it.bags),
  pallets: num(it.pallets),
  net_kg: num(it.net_kg),
  gross_kg: num(it.gross_kg),
}));

const exportRefs = Array.isArray(x.export_references) ? x.export_references.map((r) => digits(r)).filter(Boolean) : [];
const orderNumber = digits(u.order_number) || digits(x.order_number) || exportRefs[0] || '';
const bookingNo = u.booking_no || x.booking_no || null;

const login_extract = {
  order_number: orderNumber || null,
  booking_no: bookingNo,
  bl_no: x.bl_no || null,
  source_link: u.webViewLink || (u.fileId ? `https://drive.google.com/file/d/${u.fileId}/view` : ''),
  export_references: exportRefs,
  carrier: 'LOG-IN',
  vessel: up(x.vessel || ''),
  voyage: up(x.voyage || ''),
  pol: up(x.pol || ''),
  pod: up(x.pod || ''),
  shipper: up(x.shipper || ''),
  consignee: up(x.consignee || ''),
  notify: up(x.notify || ''),
  originals_to_be_released_at: x.originals_to_be_released_at ? up(x.originals_to_be_released_at) : null,
  type_of_move: x.type_of_move ? up(x.type_of_move) : null,
  destino_pais: destinoPais,
  consignee_tax: consigneeTax,
  desc,
  goods_block_raw: goodsBlock,
  equipos,
  products,
  freight: {
    concepts: outConcepts,
    totals,
    ocean_freight_kind: oceanFreightKind,
    per_container: { USD_prepaid: perUSDpre, USD_collect: perUSDcol, USD: perUSD },
    containers_for_calc: cntCont,
  },
};

return { json: { ...u, login_extract } };

/**
 * NODO Code (branch de TESTING) — "Seleccionar BL draft (orden exacta + reciente)"
 * Modo: Run Once for All Items  ·  Lenguaje: JavaScript
 *
 * Entra: salida del "GDrive — Buscar BL draft (test)" (lista de archivos de la carpeta
 *        BL DRAFT cuyo nombre matchea parcialmente el número de orden del Form).
 * Sale : 1 item con el shape que espera el normalizer ({ id, name, webViewLink, createdTime }),
 *        y EMPALMA en "Code (normalizador + Nº de orden desde el nombre)".
 *
 * Reglas (acordadas):
 *  - La orden viene del Form Trigger. Lectura DEFENSIVA del key (orden / label / primer string).
 *  - Match EXACTO de orden por la MISMA extracción del normalizer (no substring:
 *    118639311 ≠ 1186393110).
 *  - No-encontrado → throw con mensaje claro (NO silencioso; testing interno).
 *  - Múltiples → ordenar por modifiedTime desc (fallback createdTime) y tomar [0].
 */

// --- Orden desde el Form (el Search reemplaza el item, así que la leemos del nodo Form) ---
let formJson = {};
try {
  formJson = $('Form Trigger — Test por orden').first().json || {};
} catch (e) {
  formJson = {};
}
let ordenRaw = formJson.orden ?? formJson.Orden ?? formJson['Número de orden'] ?? formJson.numero_orden;
if (ordenRaw == null) {
  // fallback: primer valor string del form (key defensivo: label vs name vs lo que sea)
  ordenRaw = Object.values(formJson).find((v) => typeof v === 'string' && /\d/.test(v));
}
const ordenDigits = String(ordenRaw ?? '').trim().replace(/\D/g, '');
if (!ordenDigits) {
  throw new Error('Form sin número de orden (campo "orden" vacío o no detectado en el Form Trigger).');
}

// --- Extracción IDÉNTICA al normalizer (Nº de orden desde el nombre del archivo) ---
function ordenFromName(name) {
  const s = String(name || '');
  return (s.match(/(\d{8,12})(?=_?BL\b|_?bl\b|\.pdf$)/) || [])[1]
    || (s.match(/(\d{8,12})/) || [])[1]
    || null;
}

const files = items.map((i) => i.json).filter((f) => f && (f.id || f.fileId) && f.name);
const exact = files.filter((f) => ordenFromName(f.name) === ordenDigits);

if (exact.length === 0) {
  const vistos = files.map((f) => f.name).join(', ') || 'ninguno';
  throw new Error(`No se encontró BL draft para la orden ${ordenDigits} en BL DRAFT (archivos vistos: ${vistos}).`);
}

// Múltiples → más reciente por modifiedTime (fallback createdTime).
exact.sort((a, b) =>
  new Date(b.modifiedTime || b.createdTime || 0) - new Date(a.modifiedTime || a.createdTime || 0)
);
const pick = exact[0];

return [{
  json: {
    id: pick.id || pick.fileId,
    name: pick.name,
    webViewLink: pick.webViewLink || pick.alternateLink || '',
    createdTime: pick.createdTime || pick.modifiedTime || null,
  },
}];

/**
 * NODO Code post-IA — "Inyectar Factura"  (PUT-3, tanda Factura)
 * Modo: Run Once for Each Item · JavaScript · onError: continueRegularOutput
 * Va ENTRE "Parser Factura (IA)" (chainLlm) y "Set Factura: Join Key".
 *
 * Responsabilidades (patrón inj_booking/inj_aduana):
 *  - Passthrough del upstream que el chainLlm descarta (lee "PDF — Extract From PDF (Factura)").
 *  - Desenvuelve $json.output.factura_extract; continue-on-fail si inválido (NO rompe).
 *  - order_number SIEMPRE poblado (heredado del fan-out → LLM → filename) → Set Factura nunca sin joinKey.
 *  - CNPJs sold_to/ship_to → 14 dígitos.
 *  - grade por ítem SIEMPRE derivado con gradeFromProduct (MISMA fn que inj_login/inj_aduana) →
 *    clave de match consistente entre BL/Aduana/Factura. El endurecimiento (caso "NG 2038B") va en PUT-4.
 *  - freight_usd: FOB → null; CPT/CIF/CFR → monto del footer (lo que trajo el LLM).
 *  - factura_meta para que el COMPARADOR (PUT-4) distinga presente / ausente / duplicado.
 *
 * PE work-stream PUT 2 (ADITIVO, determinístico, NO toca campos existentes):
 *  - fob_usd, insurance_usd, freight_total, items[].amount desde el RAW (footer + fallback CFR).
 *  - Fuente FOB = footer "FOB USD <x> [FREIGHT USD <y>] [INS USD <z>] <INC> USD <total>" (CIP/CPT/CIF);
 *    fallback CFR sin footer = invoice_amount − flete − seguro. Σ amounts NO se usa como FOB (en CIP=total).
 *  - freight_usd NO se modifica (no-regresión); freight_total es el flete robusto NUEVO para el cruce PE.
 */
function up(s){return (s==null?'':String(s)).toUpperCase();}
function num(x){if(x==null)return null;const n=Number(x);return Number.isFinite(n)?n:null;}
function cleanDigits(s){return String(s||'').replace(/\D+/g,'');}
function norm14(s){const d=cleanDigits(s);return d.length>14?d.slice(-14):d;}
function gradeFromProduct(p){const t=String(p||'').toUpperCase().match(/\b[A-Z0-9]*\d[A-Z0-9]*\b/g)||[];return t.find(x=>/[0-9]/.test(x))||'';}
function orderFromName(n){const m=String(n||'').match(/(?<!\d)(\d{8,12})(?!\d)/);return m?m[1]:'';}
// PE PUT 2: USD del footer FC, formato coma-decimal ("171166,99"->171166.99 ; "186180,00"->186180).
function moneyUSD(s){if(s==null)return null;const z=String(s).replace(/[^\d.,]/g,'');if(!z)return null;const v=parseFloat(z.replace(/\./g,'').replace(',','.'));return Number.isFinite(v)?v:null;}
function round2(x){const n=Number(x);return Number.isFinite(n)?Math.round(n*100)/100:null;}

// upstream passthrough (lo que el chainLlm descartó)
let u={};
try{ u=$('PDF — Extract From PDF (Factura)').item.json||{}; }
catch(e){ console.log('[Inyectar Factura] upstream no leído:',e.message); u={}; }

// conteo filtrado por orden actual (fix Tanda F: en BL multi-orden .all() agrega runs de TODAS las órdenes)
let fcount = 1;
try {
  const _orderNum = orderFromName(u.name || '');
  const _orderStripped = _orderNum ? _orderNum.replace(/^0+/, '') : '';
  const _allGD = $('GDrive: Buscar Factura').all();
  const _cands = _orderNum
    ? _allGD.filter(it => {
        const n = String((it.json && it.json.name) || '');
        return n.indexOf(_orderNum) >= 0 || (_orderStripped && n.indexOf(_orderStripped) >= 0);
      })
    : _allGD;
  const _seen = new Set();
  const _deduped = _cands.filter(it => {
    const id = String((it.json && it.json.id) || '');
    if (!id) return true;
    if (_seen.has(id)) return false;
    return !!_seen.add(id);
  });
  fcount = _deduped.length || ((u && u.name) ? 1 : 0);
} catch(e) { fcount = (u && u.name) ? 1 : 0; }

// salida del LLM: outputParserStructured envuelve en "output"; raíz { factura_extract }
const root=($json&&$json.output)?$json.output:$json;
let fc=(root&&root.factura_extract)?root.factura_extract:root;

// REFACTURACIÓN (PUT-4): el joinKey DEBE salir del NOMBRE del archivo (conserva la orden
// ORIGINAL), NUNCA del Internal Document Number del contenido — en una FC refacturada el
// nº interno es nuevo, pero el nombre sigue con la orden original (la FC a controlar vs BL).
function stripZeros(s){ return String(s||'').replace(/^0+(?=\d)/,''); }
const orderFilename = orderFromName(u.name);                                              // autoritativo (nombre)
const orderInternal = cleanDigits((fc && (fc.internal_doc_number || fc.order_number)) || ''); // contenido
const orderResolved = orderFilename || cleanDigits(u.order_number) || orderInternal || '';
// PLANCOMPLETO-D-REFACT (2026-07-15, EXPLORE B4b): el warn de refacturación solo
// dispara si el número interno de la FC PARECE una orden (trade ^1×9 / STO ^4×10
// tras stripZeros). Los internos Dow tipo 0926… (otro esquema de numeración, jamás
// coincide con la orden) disparaban el falso positivo en CADA trade cuya factura
// mostrara el campo (casos reales: 118979844/118999177/118835832). Una
// refacturación real trae OTRA orden en la FC → sigue detectándose.
function esRefacturacion(orderFilename, orderInternal) {
  const fn = stripZeros(orderFilename), interno = stripZeros(orderInternal);
  if (!fn || !interno || fn === interno) return false;
  return /^1\d{8}$/.test(interno) || /^4\d{9}$/.test(interno);
}
const refacturacion = esRefacturacion(orderFilename, orderInternal);

// continue-on-fail: parser inválido → null + meta (NO rompe; Set Factura usa optional chaining)
if(!fc||typeof fc!=='object'||Array.isArray(fc)){
  console.log('[Inyectar Factura] factura_extract ausente/inválido — continue-on-fail. $json:', JSON.stringify($json).slice(0,400));
  return { json: { ...u, factura_extract:null, order_number:orderResolved,
                   factura_meta:{ found:true, count:fcount, duplicate:fcount>1,
                     refacturacion, order_filename:orderFilename, order_internal:orderInternal } } };
}

// CNPJs a 14 dígitos
if(fc.sold_to && typeof fc.sold_to==='object') fc.sold_to.tax = norm14(fc.sold_to.tax||'');
if(fc.ship_to && typeof fc.ship_to==='object') fc.ship_to.tax = norm14(fc.ship_to.tax||'');

// grade por ítem: SIEMPRE derivado de la descripción (misma fn que el BL) — match determinístico.
if(Array.isArray(fc.items)){
  for(const it of fc.items){
    it.grade = gradeFromProduct(it.description || it.goods || it.grade || '');
  }
  // PUT-5b: PA/NCM por ítem = "Product Code" del raw FC, en orden (zip posicional con items[]).
  // Aparece una vez por ítem ("Product Code: 39012029900U"). Sin tocar prompt/schema. Best-effort.
  const codes = [...String(u.text || '').matchAll(/Product Code:\s*([0-9A-Za-z]+)/gi)].map((m) => m[1]);
  fc.items.forEach((it, i) => { it.product_code = it.product_code || codes[i] || ''; });
  // PUT-5c: "N Bags on a Pallet" por ítem (zip posicional) → pallets = bolsas / N (NO hardcodear 60).
  const perPallet = [...String(u.text || '').matchAll(/(\d+)\s*Bags on a Pallet/gi)].map((m) => num(m[1]));
  fc.items.forEach((it, i) => {
    it.bags_per_pallet = perPallet[i] || perPallet[0] || null;
    const b = num(it.bags);
    it.pallets = (b != null && it.bags_per_pallet) ? Math.round(b / it.bags_per_pallet) : null;
  });
  // PUT-5d: embalaje por ítem desde el raw ("25 KG Bags"), zip posicional. Sin tocar prompt.
  const embs = [...String(u.text || '').matchAll(/(\d+\s*KG\s+Bags?)/gi)].map((m) => m[1].replace(/\s+/g, ' ').trim());
  fc.items.forEach((it, i) => { it.embalaje = it.embalaje || embs[i] || embs[0] || ''; });
}

// PUT-5c: Exportador/emisor de la FC (dirección completa) desde el raw — bloque PBBPOLISUR hasta "Condition:".
// Sin tocar prompt. El COMPARADOR/plantilla lo compara contra el shipper del BL (deben coincidir).
function exporterFromRaw(txt) {
  const t = String(txt || '');
  let m = /(PBBPOLISUR[\s\S]*?)\n\s*Condition\s*:/i.exec(t);
  if (!m) m = /(PBBPOLISUR[^\n]*(?:\n[^\n]*){0,4})/i.exec(t);
  if (!m) return '';
  return m[1].replace(/\r/g, '').split('\n').map((s) => s.trim()).filter(Boolean).join('\n');
}
fc.exporter = exporterFromRaw(u.text);

// freight: FOB → no se factura el flete (null); CPT/CIF/CFR → monto del footer
const inc=up(fc.incoterm||'');
const isFob=/^FOB/.test(inc);
fc.freight_usd = isFob ? null : num(fc.freight_usd);

// order_number CRUDO (el strip de ceros vive SOLO en Set Factura)
fc.order_number = orderResolved;
fc.source_link = u.webViewLink
  || (u.fileId ? `https://drive.google.com/file/d/${u.fileId}/view`
     : (u.id ? `https://drive.google.com/file/d/${u.id}/view` : ''));

// ===== PE work-stream PUT 2 — FOB / SEGURO / amount por ítem (ADITIVO, determinístico) =====
// NO se modifica ningún campo existente (incl. freight_usd). Sólo se agregan claves nuevas.
{
  const _t = String(u.text || '');
  const _mFob = _t.match(/FOB\s+USD\s+([\d.,]+)/i);     // footer (CIP/CPT/CIF)
  const _mFrtFooter = _t.match(/FREIGHT\s+USD\s+([\d.,]+)/i); // footer flete (CIP/CPT/CIF)
  const _mFrtLine = _t.match(/\bFREIGHT\s+([\d.,]+)/i);  // ítem "FREIGHT 2.576,00" (CFR, sin "USD")
  const _mIns = _t.match(/\bINS\s+USD\s+([\d.,]+)/i);    // seguro (sólo CIF/CIP)
  const footerFob = _mFob ? moneyUSD(_mFob[1]) : null;
  const footerFrt = _mFrtFooter ? moneyUSD(_mFrtFooter[1]) : null;
  const lineFrt   = (!_mFrtFooter && _mFrtLine) ? moneyUSD(_mFrtLine[1]) : null; // sólo si NO hay "FREIGHT USD"
  const footerIns = _mIns ? moneyUSD(_mIns[1]) : null;

  // seguro: footer INS si está; null si no (CFR/CPT/FOB no llevan)
  fc.insurance_usd = footerIns;
  // flete robusto NUEVO (no pisa freight_usd): footer FREIGHT USD → LLM freight_usd → ítem FREIGHT (CFR)
  const _llmFrt = num(fc.freight_usd);
  fc.freight_total = (footerFrt != null) ? footerFrt : (_llmFrt != null ? _llmFrt : lineFrt);
  // FOB total: footer si está; fallback CFR (sin footer) = invoice − flete − seguro
  const _inv = num(fc.totals && fc.totals.invoice_amount);
  fc.fob_usd = (footerFob != null) ? footerFob
    : ((_inv != null) ? round2(_inv - (fc.freight_total || 0) - (footerIns || 0)) : null);

  // amount por ítem (best-effort; chequeos intra-doc, NO fuente del FOB total — decisión #3/#9).
  // Ancla: "<amount> 0,00 0,00 0<materialCode>" (la línea de cada ítem de producto).
  if (Array.isArray(fc.items)) {
    const amts = [..._t.matchAll(/([\d.,]+)\s+0,00\s+0,00\s+0\d{6,}/g)].map((m) => moneyUSD(m[1]));
    fc.items.forEach((it, i) => { it.amount = (amts[i] != null ? amts[i] : null); });
  }
}

return { json: { ...u, factura_extract:fc, order_number:orderResolved,
                 factura_meta:{ found:true, count:fcount, duplicate:fcount>1,
                   refacturacion, order_filename:orderFilename, order_internal:orderInternal } } };

/**
 * NODO Code post-IA — "Inyectar metadata (MAERSK)"
 * Modo: Run Once for Each Item · JavaScript · onError: continueRegularOutput
 * Va ENTRE "Parser MAERSK (IA)" (chainLlm) y el fan-out (Buscar Aduana / Buscar Booking /
 * Set BL Join Key / Buscar Factura) — espejo del "Inyectar metadata (LOG-IN)".
 *
 * CONTRATO: emite la clave `login_extract` (la consumen COMPARADOR y plantilla tal cual)
 * con carrier:'MAERSK'. Downstream INTACTO — cero cambios fuera de la rama Maersk.
 *
 * Diferencias vs LOG-IN (layout Maersk):
 *  - Raíz del LLM: maersk_extract (D1) → acá se traduce a login_extract.
 *  - Números US (punto decimal) — el LLM ya emite números JSON.
 *  - Equipos SIN peso neto por contenedor (nw=null → celda NODATA en el comparador, sin falso REVISAR).
 *  - measurement: CBM US → string formato EUROPEO ("32.371" → "32,3710") porque el comparador
 *    lo parsea con parseNumberEU. [D3 BASE — refinar mañana]
 *  - wooden global del BL replicado a cada contenedor. [D2 BASE — refinar mañana]
 *  - destino_pais: mapa con MEXICO (los Maersk van también a México/USA). [D5 BASE — refinar mañana]
 *  - Regexes de texto crudo sobre versión whitespace-normalizada (el extract Maersk parte
 *    palabras/líneas en cualquier lado) con fallback SIEMPRE a los campos del LLM.
 *  - Safety-dedupe de equipos por contenedor (el PDF trae el documento repetido 2-3×).
 */

const UP_NODE = 'Switch (ruteo por naviera + validación de orden)';

function up(s) { return (s == null ? '' : String(s)).toUpperCase(); }
function num(x) { if (x == null) return null; const n = Number(x); return Number.isFinite(n) ? n : null; }
function digits(s) { return String(s || '').replace(/[^\d]/g, ''); }
function round2(x) { return Math.round((Number(x) || 0) * 100) / 100; }
function cur3(s) { return up(s) === 'BRL' ? 'BRL' : 'USD'; }
// Texto aplanado para regexes: el extract de Maersk corta líneas (a veces palabras) en
// cualquier punto — los patrones de datos se buscan sobre una copia con whitespace colapsado.
function flat(s) { return String(s || '').replace(/\s+/g, ' '); }
// Token de grade desde la descripción del producto (copia EXACTA de inj_aduana / inj_login —
// clave de match cross-doc). Primer token alfanumérico que contiene un dígito.
function gradeFromProduct(p) {
  const toks = String(p || '').toUpperCase().match(/\b[A-Z0-9]*\d[A-Z0-9]*\b/g) || [];
  return toks.find((t) => /[0-9]/.test(t)) || '';
}

// ---- upstream passthrough (lo que el chainLlm descartó) ----
let u = {};
try { u = $(UP_NODE).item.json || {}; }
catch (e) { console.log('[Inyectar MAERSK] upstream no leído:', e.message); u = {}; }

// ---- salida del LLM: outputParserStructured envuelve en "output"; raíz { maersk_extract } ----
const root = ($json && $json.output) ? $json.output : $json;
let x = (root && root.maersk_extract) ? root.maersk_extract : root;

// continue-on-fail: si el parser IA no produjo objeto válido, log + passthrough sin romper.
if (!x || typeof x !== 'object' || Array.isArray(x) || (!x.description && !x.equipos)) {
  console.log('[Inyectar MAERSK] maersk_extract ausente/inválido — continue-on-fail. $json:',
    JSON.stringify($json).slice(0, 500));
  return { json: { ...u, login_extract: null } };
}

const d = x.description || {};
const rawText = String(u.text || '');
const flatText = flat(rawText);

// ===== FREIGHT — reconciliación de balance (porta la lógica del inyector LOG-IN) =====
const fl = x.freight_lines || {};
const rawConcepts = Array.isArray(fl.concepts) ? fl.concepts : [];
const rawTotals = Array.isArray(fl.totals_lines) ? fl.totals_lines : [];

// Marcador textual del BL ("FREIGHT PREPAID"/"FREIGHT COLLECT"): LLM primero, regex de respaldo.
const markerText = (flatText.match(/FREIGHT\s+(PREPAID|COLLECT)/i) || [])[1] || '';
const freightMarker = up(fl.freight_marker || markerText || '');

const totals = { USD: { prepaid: 0, collect: 0 }, BRL: { prepaid: 0, collect: 0 } };
for (const t of rawTotals) {
  const c = cur3(t.currency);
  totals[c].prepaid = num(t.prepaid_amount) || 0;
  totals[c].collect = num(t.collect_amount) || 0;
}

const concepts = [...rawConcepts].sort((a, b) => (num(a.line_number) ?? 0) - (num(b.line_number) ?? 0));
const rem = {
  USD: { prepaid: totals.USD.prepaid, collect: totals.USD.collect },
  BRL: { prepaid: totals.BRL.prepaid, collect: totals.BRL.collect },
};
const outConcepts = [];
for (const c of concepts) {
  const cu = cur3(c.currency);
  const amt = num(c.amount);
  let kind = null;
  if (amt != null) {
    const canPre = amt <= (rem[cu]?.prepaid ?? 0);
    const canCol = amt <= (rem[cu]?.collect ?? 0);
    if (canPre && (!canCol || amt === (rem[cu]?.prepaid ?? 0))) {
      kind = 'PREPAID'; rem[cu].prepaid -= amt;
    } else if (canCol) {
      kind = 'COLLECT'; rem[cu].collect -= amt;
    } else {
      const col = (c.column || '').toLowerCase();
      if (col === 'left') kind = 'PREPAID';
      else if (col === 'right') kind = 'COLLECT';
      else kind = freightMarker === 'COLLECT' ? 'COLLECT' : 'PREPAID';
    }
  }
  outConcepts.push({
    concept: c.concept || '',
    kind,
    currency: cu,
    amount: amt,
    rate_currency: cur3(c.rate_currency),
    rate: num(c.rate),
  });
}

let oceanFreightKind = '';
for (const c of outConcepts) {
  const name = up(c.concept);
  if (name.includes('OCEAN') && name.includes('FREIGHT') && (c.kind === 'PREPAID' || c.kind === 'COLLECT')) {
    oceanFreightKind = c.kind; break;
  }
}
// Respaldo: el marcador textual del BL manda si la reconciliación no decidió.
if (!oceanFreightKind && (freightMarker === 'PREPAID' || freightMarker === 'COLLECT')) {
  oceanFreightKind = freightMarker;
}

// ===== DESC totals — items del LLM como primario, regex de texto como verificación =====
const items = Array.isArray(d.items) ? d.items : [];
const hasItems = items.length > 0;
const sumItems = (f) => items.reduce((s, it) => s + (num(it[f]) || 0), 0);

// Patrón "{X} BAGS IN {Y} PALLETS" scopeado a la PRIMERA copia del bloque de mercadería
// (header "Kind of Packages..." → "Above particulars"): el doc viene repetido 3× y dos productos
// pueden tener cantidades IDÉNTICAS — contar pares crudos dentro de una sola copia evita ambos
// bugs (un Set global colapsaría los idénticos; contar todo el doc triplicaría).
// Recalibrado contra los 32 textos reales del extractFromFile (§3.5 del plan, 2026-06-11).
const parseCount = (s) => { const n = parseInt(String(s).replace(/[.,\s]/g, ''), 10); return Number.isFinite(n) ? n : null; };
const RE_GOODS_HDR = /Kind of Packages;?\s*Description of goods[^\n]*\n/i;
const RE_GOODS_END = /Above particulars|SHIPPER'?S?\s+LOAD|Freight\s*&\s*Charges|VERY\s+IMPORTANT/i;
const RE_BAGS = () => /(\d[\d.,]*)\s*BAGS?\s+IN\s+(\d[\d.,]*)\s*PALLETS?/gi;
const bagsPalletsFromText = (txt) => {
  const t = String(txt || '');
  const hdr = RE_GOODS_HDR.exec(t);
  if (hdr) {
    const rest = t.slice(hdr.index + hdr[0].length);
    const end = RE_GOODS_END.exec(rest);
    const scope = flat(end ? rest.slice(0, end.index) : rest);
    let m, b = 0, p = 0, blocks = 0;
    const rx = RE_BAGS();
    while ((m = rx.exec(scope)) !== null) {
      const bb = parseCount(m[1]); const pp = parseCount(m[2]);
      if (bb != null && pp != null) { b += bb; p += pp; blocks++; }
    }
    if (blocks) return { bags: b, pallets: p, blocks };
  }
  // Fallback (header no reconocible, ej. texto degradado): pares ÚNICOS sobre todo el texto —
  // tolera las copias repetidas a costa de colapsar productos con cantidades idénticas.
  const pairs = new Set();
  let m;
  const rx = RE_BAGS();
  while ((m = rx.exec(flat(t))) !== null) {
    const bb = parseCount(m[1]); const pp = parseCount(m[2]);
    if (bb != null && pp != null) pairs.add(`${bb}|${pp}`);
  }
  if (!pairs.size) return null;
  let b = 0, p = 0;
  for (const k of pairs) { const [bb, pp] = k.split('|').map(Number); b += bb; p += pp; }
  return { bags: b, pallets: p, blocks: pairs.size };
};
const bpText = bagsPalletsFromText(rawText);
const bpUsable = bpText && (!hasItems || bpText.blocks >= items.length);

const bolsas = bpUsable ? bpText.bags : (hasItems ? sumItems('bags') : num(d.bags_total));
const pallets = bpUsable ? bpText.pallets : (hasItems ? sumItems('pallets') : num(d.pallets_total));
const net = (hasItems && sumItems('net_kg') > 0) ? sumItems('net_kg') : num(d.net_total_kg);

// ===== EQUIPOS — dedupe por contenedor + wooden global + measurement EU =====
const woodenMat = up(d.wooden_material || '');
const woodenCond = up(d.wooden_condition || '');
// CBM US (número) → string formato EUROPEO para parseNumberEU del comparador ("32.371" → "32,371").
// [D3 BASE — refinar mañana: precisión/redondeo vs Volume del Booking]
const cbmToEU = (v) => { const n = num(v); return n == null ? '' : String(n).replace('.', ','); };

const seenCont = new Set();
const equipos = [];
for (const e of (Array.isArray(x.equipos) ? x.equipos : [])) {
  const cont = up(e && e.container || '');
  if (!cont || seenCont.has(cont)) continue;   // safety-dedupe (doc repetido 2-3×)
  seenCont.add(cont);
  equipos.push({
    container: cont,
    seal: up(e.seal || ''),
    nw: null,                                   // Maersk no trae neto por contenedor — NODATA río abajo
    gw: num(e.gross_kg),
    measurement: cbmToEU(e.cbm),
    wooden_material: woodenMat,                 // [D2 BASE] global del BL replicado por contenedor
    wooden_conditions: woodenCond,
  });
}

// Gross total: suma de items si el LLM la trae completa; si no, suma de los gw de equipos
// (en Maersk el bruto por contenedor es confiable y cuadra con la línea total "NNNNN.NNN KGS").
const grossItems = hasItems ? sumItems('gross_kg') : 0;
const grossEquipos = equipos.reduce((s, e) => s + (e.gw || 0), 0);
const gross = grossItems > 0 ? grossItems : (grossEquipos > 0 ? round2(grossEquipos) : num(d.gross_total_kg));

const cntCont = (num(d.cantidad_contenedores) ?? 0) || equipos.length || 0;
let perUSDpre = 0, perUSDcol = 0;
if (cntCont > 0) {
  if (oceanFreightKind === 'PREPAID') perUSDpre = round2(totals.USD.prepaid / cntCont);
  else if (oceanFreightKind === 'COLLECT') perUSDcol = round2(totals.USD.collect / cntCont);
}
const perUSD = perUSDpre || perUSDcol || 0;

// ===== PE, destino_pais, CNPJ, goods block desde el raw =====
// PE (Permiso de Embarque): mismo patrón que LOG-IN — en Maersk viene como "PE: 26033EC01003851K"
// dentro del bloque de mercadería. Sobre texto aplanado (tolera saltos de línea del extract).
const peFromText = (flatText.match(/\b\d{5}EC\d{8}[A-Z]\b/) || [])[0] || '';

// Bloque de mercadería TAL CUAL desde el raw (para el render monoespaciado del mail).
// Header Maersk: "Kind of Packages; Description of goods...". Corte recalibrado contra los 32
// textos reales (§3.5): "Above particulars" cierra 32/32; SHIPPER'S LOAD/etc quedan de respaldo
// (en algunos BL aparecen antes y dan un corte igualmente limpio).
function goodsBlockRaw(txt) {
  const t = String(txt || '');
  const hdr = RE_GOODS_HDR.exec(t);
  let block = '';
  if (hdr) {
    const rest = t.slice(hdr.index + hdr[0].length);
    const end = RE_GOODS_END.exec(rest);
    block = (end ? rest.slice(0, end.index) : rest).trim().slice(0, 4000);
  }
  // FIX 4 (hallazgo 1, 2026-06-11): en el layout WAYBILL la ventana header→"Above particulars"
  // contiene solo el boilerplate "Below freight details will not be part of..." (sin un solo
  // dígito de carga) y el bloque real "N Container Said to Contain..." queda linearizado
  // DESPUÉS del end-marker, pegado al Notify Party. Gate: ventana sin dígitos → anclar por
  // CONTENIDO. Los ocean/multimodal traen dígitos en la ventana (pallets/KGS/contenedores)
  // → el gate NO se activa y conservan el corte actual sin cambios.
  if (!/\d/.test(block)) {
    const anchor = /\d+\s*Containers?\s+Said\s+to\s+Contain/i.exec(t);
    if (anchor) {
      const rest2 = t.slice(anchor.index);
      const end2 = /The\s+Merchant\(?s?\)?\s+warrant|Above particulars|\nPage\s*:|\nConsignee\b|Signed\s+for\s+the\s+Carrier/i.exec(rest2);
      block = (end2 ? rest2.slice(0, end2.index) : rest2).trim().slice(0, 4000);
    }
  }
  if (!block) return '';
  // FIX 2 (2026-06-11): la línea FINAL de totales del BL Maersk ("37131.600 KGS 58.6730 CBM")
  // se normaliza a "<gross> <meas>" sin unidades — es el formato que el parser de la caja
  // verbatim de la plantilla (compartida, intocable) reconoce como última línea para poblar
  // los campos GROSS WEIGHT y MEASUREMENT en vez de dejarlos dentro de DESCRIPTION.
  // Las líneas por contenedor (con KGS/CBM intermedios) quedan tal cual en DESCRIPTION.
  block = block.replace(/(^|\n)\s*([\d.,]+)\s*KGS\s+([\d.,]+)\s*CBM\s*$/i, '$1$2 $3');
  return block;
}
const goodsBlock = goodsBlockRaw(rawText);

// destino_pais desde el país del consignee. [D5 BASE] + MEXICO (Maersk va también a MX/US).
function destinoFromConsignee(cons) {
  const t = up(cons);
  const map = [['BRASIL', 'BRAZIL'], ['BRAZIL', 'BRAZIL'], ['ARGENTINA', 'ARGENTINA'], ['URUGUAY', 'URUGUAY'],
    ['PARAGUAY', 'PARAGUAY'], ['CHILE', 'CHILE'], ['MEXICO', 'MEXICO'], ['MÉXICO', 'MEXICO'],
    ['ESTADOS UNIDOS', 'UNITED STATES'], ['UNITED STATES', 'UNITED STATES'], ['USA', 'UNITED STATES']];
  for (const [k, v] of map) { if (t.includes(k)) return v; }
  return '';
}
const destinoPais = destinoFromConsignee(x.consignee || '');

// Tax ID del consignee: CNPJ (Brasil, 14 díg) + RUC (Perú, 11 díg) + RFC (México, alfanumérico).
// FIX 5 (hallazgo 2, 2026-06-11): el comparador (compartido, intocable) normaliza con norm14,
// que colapsa a dígitos y solo trunca si >14 — un RUC-11 igual en BL y BA compara consistente
// sin tocar nada río abajo. CNPJ-14 conserva el comportamiento exacto (slice(-14)).
function extractCNPJ(text) {
  const t = String(text || '');
  // IDs numéricos con label: CNPJ/TAX ID/RUC — mínimo 8 dígitos (RUC=11, CNPJ=14).
  let m = t.match(/(?:CNPJ|TAX\s*ID|RUC)\s*[:.\-]?\s*([\d][\d.\/-]{7,20})/i);
  if (m) {
    const dd = m[1].replace(/\D/g, '');
    if (dd.length >= 14) return dd.slice(-14);
    if (dd.length >= 8) return dd;
  }
  // RFC mexicano (3-4 letras + 6 dígitos fecha + homoclave), con o sin espacios: "DQM 590909 RK0".
  m = t.match(/(?:RFC|TAX\s*ID)\s*[:.\-]?\s*([A-ZÑ&]{3,4}\s?\d{6}\s?[A-Z0-9]{2,3})\b/i);
  if (m) return m[1].replace(/\s+/g, '').toUpperCase();
  m = t.match(/\b\d{2}\.\d{3}\.\d{3}\/\d{4}-\d{2}\b/);
  if (m) return m[0].replace(/\D/g, '');
  m = t.match(/\b\d{14}\b/);
  if (m) return m[0];
  return '';
}
const consigneeTax = extractCNPJ(x.consignee || '');

// type_of_move: LLM o patrón "CY/CY" del raw.
const typeOfMove = x.type_of_move || (flatText.match(/\b(CY\s*\/\s*CY|CY\/SD|SD\/CY|FCL\/FCL)\b/i) || [])[0] || null;

// FIX 1 (2026-06-11): notify "SAME AS CONSIGNEE" → resolver al CONSIGNEE del propio BL
// (nombre + dirección + CNPJ). El LLM transcribe el notify LITERAL; la resolución es
// determinística acá. El comparador (compartido, intocable) compara notify-BL vs notify-BA
// normal: matchea por CNPJ/email → BA notify = consignee → coincide ✓; ≠ → REVISAR.
const notifyRaw = String(x.notify || '');
const notifyResolved = /^\s*SAME\s+AS\s+(THE\s+)?CONSIGNEE\s*\.?\s*$/i.test(notifyRaw)
  ? String(x.consignee || '') : notifyRaw;

// ===== TRADUCTOR: snake_case → keys verbatim del contrato =====
const desc = {
  "DESC BL - CANTIDAD DE CONTENEDORES": num(d.cantidad_contenedores) ?? (equipos.length || null),
  "DESC BL - GOODS (DESCRIPCIÓN CRUDA)": up(d.goods_raw || ''),
  "DESC BL - PRODUCTO": up(d.producto || ''),
  "DESC BL - GRADE / CALIDAD": up(d.grade || ''),
  "DESC BL - TIPO DE EMBALAJE": up(d.embalaje || ''),
  "DESC BL - CANTIDAD DE BOLSAS": bolsas ?? null,
  "DESC BL - CANTIDAD DE PALLETS": pallets ?? null,
  "DESC BL - NCM": up(d.ncm || ''),
  "DESC BL - PESO BRUTO TOTAL (KG)": gross ?? null,
  "DESC BL - PESO NETO TOTAL (KG)": net ?? null,
  "DESC BL - PE (PERMISO DE EMBARQUE)": peFromText || up(d.pe_code || ''),
};

// productos[] por item del LLM (multiproducto). Igual que LOG-IN: se PROPAGAN sin tocar totales.
const products = items.map((it) => ({
  goods: up(it.goods || ''),
  grade: gradeFromProduct(it.goods || ''),
  bags: num(it.bags),
  pallets: num(it.pallets),
  net_kg: num(it.net_kg),
  gross_kg: num(it.gross_kg),
}));
// FIX 3 REVERTIDO (2026-06-11, decisión John): asignar el bruto global al producto mono
// destapaba un falso REVISAR por el bug de floats de buildProductos (comparador COMPARTIDO:
// igualdad estricta + Aduana acumulada sin redondeo). El "0,00" cosmético del desglose es
// preferible; el float-bug va a la tanda de hardening del comparador (con regresión Log-In).

const exportRefs = Array.isArray(x.export_references) ? x.export_references.map((r) => digits(r)).filter(Boolean) : [];
const orderNumber = digits(u.order_number) || digits(x.order_number) || exportRefs[0] || '';
const bookingNo = u.booking_no || x.booking_no || null;

const login_extract = {
  order_number: orderNumber || null,
  booking_no: bookingNo,
  bl_no: x.bl_no || x.booking_no || null,     // en Maersk B/L No. == Booking No.
  source_link: u.webViewLink || (u.fileId ? `https://drive.google.com/file/d/${u.fileId}/view` : ''),
  export_references: exportRefs,
  carrier: 'MAERSK',
  vessel: up(x.vessel || ''),
  voyage: up(x.voyage || ''),
  pol: up(x.pol || ''),
  pod: up(x.pod || ''),
  shipper: up(x.shipper || ''),
  consignee: up(x.consignee || ''),
  notify: up(notifyResolved || ''),
  originals_to_be_released_at: null,          // Maersk no trae (10A) — el comparador lo saltea con null
  type_of_move: typeOfMove ? up(typeOfMove) : null,
  destino_pais: destinoPais,
  consignee_tax: consigneeTax,
  desc,
  goods_block_raw: goodsBlock,
  equipos,
  products,
  freight: {
    concepts: outConcepts,
    totals,
    ocean_freight_kind: oceanFreightKind,
    per_container: { USD_prepaid: perUSDpre, USD_collect: perUSDcol, USD: perUSD },
    containers_for_calc: cntCont,
  },
};

return { json: { ...u, login_extract } };

/**
 * NODO Code post-IA — "Inyectar PE"  (work-stream PE — PUT 1, rama de ingesta)
 * Modo: Run Once for Each Item · JavaScript · onError: continueRegularOutput
 * Va ENTRE "Parser PE (IA)" (chainLlm) y "Set PE: Join Key".
 *
 * Responsabilidades (patrón inj_factura/inj_booking):
 *  - Passthrough del upstream que el chainLlm descarta (lee "PDF — Extract From PDF (PE)").
 *  - Desenvuelve $json.output.pe_extract; continue-on-fail si inválido (NO rompe; Set PE usa optional chaining).
 *  - order_number SIEMPRE desde el NOMBRE del archivo PE ({destinacion}_{orden}_PE.pdf). OJO: el
 *    order_number del fan-out NO sobrevive al nodo de búsqueda Drive (el search reemplaza el json
 *    con la metadata del archivo). El filename es el único portador de la orden río abajo.
 *  - NO usar el orderFromName genérico (\d{8,12}): el prefijo Destinación ("26003EC01003967P")
 *    contiene "01003967" (8 díg) y lo agarraría como orden. Acá la orden se ancla con _(\d{8,12})_PE.
 *  - destinacion_sim AUTORITATIVO desde el filename (lo nombró el clasificador a partir del PE);
 *    la extracción del cuerpo por IA queda como fallback. Endurece el cruce #1 (permiso).
 *  - source_link para el botón "Abrir PE" del mail.
 *  - pe_meta {found, count} para trazabilidad (PE ausente NO llega acá: la rama no corre con 0 ítems →
 *    el doc llega al COMPARADOR sin pe_extract; ese es el patrón "PE ausente" = NODATA, decisión #1).
 *
 * NOTA decisión #1: PE faltante NO es un missing_doc. buildGuard NO lo agrega. Acá no hay nada que
 * hacer para el caso ausente: simplemente este nodo no se ejecuta (rama vacía).
 */
function num(x){ if(x==null) return null; const n=Number(x); return Number.isFinite(n)?n:null; }
function up(s){ return (s==null?'':String(s)).toUpperCase(); }
// Orden anclada al sufijo _<orden>_PE (evita capturar el serial del permiso del prefijo Destinación).
function orderFromPEName(n){ const m=String(n||'').match(/_(\d{8,12})_PE/i); return m?m[1]:''; }
// Destinación SIM = primer token del filename (lo escribió el clasificador desde el permiso).
function destFromPEName(n){ const m=String(n||'').match(/^([0-9A-Za-z]+)_\d{8,12}_PE/i); return m?up(m[1]):''; }
// normalización permiso: upper + sin espacios (espejo de normPE del comparador) — el cuerpo del PE
// trae el permiso con espacios ("26 003 EC01 003967 P").
function normPE(s){ return up(s).replace(/\s+/g,''); }

// upstream passthrough (lo que el chainLlm descartó: name, webViewLink/id, text)
let u={};
try{ u=$('PDF — Extract From PDF (PE)').item.json||{}; }
catch(e){ console.log('[Inyectar PE] upstream no leído:',e.message); u={}; }

// conteo de PEs por orden (paridad con Inyectar Factura; PE es 1/orden, pero protege multi-orden)
let pcount=1;
try{
  const _ord=orderFromPEName(u.name||'');
  const _stripped=_ord?_ord.replace(/^0+/,''):'';
  const _all=$('GDrive: Buscar PE').all();
  const _cands=_ord
    ? _all.filter(it=>{ const n=String((it.json&&it.json.name)||''); return n.indexOf(_ord)>=0 || (_stripped&&n.indexOf(_stripped)>=0); })
    : _all;
  const _seen=new Set();
  const _dedup=_cands.filter(it=>{ const id=String((it.json&&it.json.id)||''); if(!id) return true; if(_seen.has(id)) return false; return !!_seen.add(id); });
  pcount=_dedup.length || ((u&&u.name)?1:0);
}catch(e){ pcount=(u&&u.name)?1:0; }

const orderFilename=orderFromPEName(u.name||'');
const destFilename=destFromPEName(u.name||'');
const orderResolved=orderFilename || String(u.order_number||'').replace(/\D/g,'') || '';
const source_link = u.webViewLink
  || (u.fileId ? `https://drive.google.com/file/d/${u.fileId}/view`
     : (u.id ? `https://drive.google.com/file/d/${u.id}/view` : ''));

// salida del LLM: outputParserStructured envuelve en "output"; raíz { pe_extract }
const root=($json&&$json.output)?$json.output:$json;
let pe=(root&&root.pe_extract)?root.pe_extract:root;

// continue-on-fail: parser inválido → null + meta (NO rompe)
if(!pe || typeof pe!=='object' || Array.isArray(pe)){
  console.log('[Inyectar PE] pe_extract ausente/inválido — continue-on-fail. $json:', JSON.stringify($json).slice(0,400));
  return { json: { ...u, pe_extract:null, order_number:orderResolved,
                   pe_meta:{ found:true, count:pcount, duplicate:pcount>1, order_filename:orderFilename } } };
}

// destinacion_sim AUTORITATIVO desde el filename; IA como fallback. (cross #1 robusto)
const destLLM=normPE(pe.destinacion_sim||'');
pe.destinacion_sim = destFilename || destLLM || null;
if(destFilename && destLLM && destFilename!==destLLM){
  pe.destinacion_mismatch = { filename: destFilename, body: destLLM };  // visible si difieren (no debería)
}

// números (paridad de tipo; el LLM ya los manda en punto, esto sólo coacciona)
pe.fob_total    = num(pe.fob_total);
pe.flete_total  = num(pe.flete_total);
pe.seguro_total = num(pe.seguro_total);
pe.total_bultos = num(pe.total_bultos);
pe.peso_bruto   = num(pe.peso_bruto);
pe.cond_venta   = pe.cond_venta ? up(pe.cond_venta) : null;
if(Array.isArray(pe.items)){
  pe.items=pe.items.map(it=>({
    posicion_sim: it&&it.posicion_sim!=null?String(it.posicion_sim):null,
    descripcion: it&&it.descripcion!=null?String(it.descripcion):'',
    kg_neto: num(it&&it.kg_neto),
    fob_item: num(it&&it.fob_item),
  }));
} else { pe.items=[]; }

pe.order_number=orderResolved;
pe.source_link=source_link;

return { json: { ...u, pe_extract:pe, order_number:orderResolved,
                 pe_meta:{ found:true, count:pcount, duplicate:pcount>1, order_filename:orderFilename } } };

// Armar fila Control BL — arma el payload del UPSERT a bl_controls
// (?on_conflict=order_number,bl_file_id + merge-duplicates — PLAN1 T1).
// PLAN1-FIX6 (2026-07-14): el payload YA NO incluye email_sent ni email_sent_at.
// Esos campos los escribe ÚNICAMENTE el nodo "Claim envío (email_sent)"
// (test-and-set atómico justo antes del send) y los revierte "Revertir claim"
// si Gmail falla — mismo patrón idempotente que Armar fila Mailing usa con
// status/sent_*: un re-run del control actualiza el análisis SIN pisar el
// estado de envío. Consecuencia: 1 (un) mail por versión de BL
// (order_number + bl_file_id); doble disparo trigger+form ya no duplica.
// Lee body_html/subject/email_to del item actual (salida per-item de
// "code  - plantilla HTML") y los estructurados del COMPARADOR (doc + result).
// Devuelve UN objeto cuyas keys == columnas de bl_controls.
const tpl = $json;

// COMPARADOR: preferir paired item; si el template rompió el pairing, caer a first().
let c;
try { c = $('COMPARADOR - BL vs Aduana vs Booking').item.json; }
catch (e) { c = $('COMPARADOR - BL vs Aduana vs Booking').first().json; }
c = c || {};

const bl  = c.login_extract   || {};   // BL: clave uniforme LOG-IN y MAERSK (carrier adentro)
const adu = c.aduana_extract  || {};
const ba  = c.booking_extract || {};
const fc  = c.factura_extract || {};
const pe  = (c.pe_extract === undefined ? null : c.pe_extract);   // PE puede ser null (ausente)
const cs  = c.compare_summary || {};
const kf  = cs.key_fields || {};
const cmp = c.compare || {};
const cnt = cmp.counters || {};
const hr  = c.header_resumen || {};

const pick = (...xs) => {
  for (const x of xs) { if (x !== undefined && x !== null && String(x).trim() !== '') return x; }
  return null;
};
const driveId = (u) => { const m = String(u || '').match(/\/d\/([^/]+)/); return m ? m[1] : null; };
const intOr0  = (x) => Number.isFinite(Number(x)) ? Number(x) : 0;

const order_number = pick(c.order_number, (kf.order_number||{}).BL, (kf.order_number||{}).Aduana, (kf.order_number||{}).BA, c.joinKey, bl.order_number, ba.order_number);
const booking_no   = pick((kf.booking_no||{}).BL, (kf.booking_no||{}).BA, c.booking_no, bl.booking_no, ba.booking_no, hr.booking);
const bl_number    = pick(kf.bl_number, bl.bl_no);
const carrier      = pick(bl.carrier, c.carrier_name, c.carrier_code);
const vessel       = pick(bl.vessel, hr.vessel);
const voyage       = pick(bl.voyage);
const pol          = pick((kf.pol||{}).BL, bl.pol);
const pod          = pick((kf.pod||{}).BL, bl.pod);

// overall_result: NOT NULL + CHECK in ('OK','REVISAR'). Fallback 'REVISAR' (marca para revisar) si vino raro.
const overall_result = (cmp.overall === 'OK' || cmp.overall === 'REVISAR') ? cmp.overall : 'REVISAR';

const email_to = Array.isArray(tpl.email_to)
  ? tpl.email_to.join(', ')
  : (tpl.email_to != null && String(tpl.email_to).trim() !== '' ? String(tpl.email_to) : null);

const row = {
  // claves / identidad
  order_number, booking_no, bl_number, carrier, vessel, voyage, pol, pod,
  // resultado
  overall_result,
  ok_count:      intOr0(cnt.OK),
  revisar_count: intOr0(cnt.REVISAR),
  // jsonb crudos
  bl_extract:      bl,
  aduana_extract:  adu,
  booking_extract: ba,
  factura_extract: fc,
  pe_extract:      pe,
  comparison:           c.compare_bl_anchored || {},   // OBJETO {campos,totales} (la col defaultea '[]' pero acepta objeto)
  equipment_comparison: c.compare_equipos     || [],
  // links (best-effort; el body_html ya los trae embebidos)
  bl_drive_link:      bl.source_link || null,
  bl_file_id:         driveId(bl.source_link),
  aduana_drive_link:  adu.source_link || c.aduana_link || null,
  booking_drive_link: (ba.links && ba.links.webViewLink) || null,
  // mail (el ESTADO de envío no viaja acá — es del claim; ver header)
  email_to,
  // render verbatim
  body_html: tpl.body_html || null,
  subject:   tpl.subject   || null,
  // explícitos para NO heredar defaults mentirosos (tokens/costos = Fase 2 del proyecto)
  model_used:  null,   // la col defaultea a 'claude-haiku-...' → DEBE ir null explícito
  ai_summary:  null,
  ai_analysis: null,   // la col defaultea a '{}' → null explícito
  operacion_id: null,  // sin fuente confiable en este workflow (FK nullable)
};

return { json: row };

// Detectar persistencia fallida — rama de alerta (best-effort, continue-on-fail).
// La salida de "Persistir Control BL": en ÉXITO trae la fila insertada CON `id` (Supabase
// devuelve representation). En FALLO (continue-on-fail tras 401/RLS/etc.) viene sin `id`.
// Si persistió OK → return [] (no dispara la alerta). Si falló → emite 1 item con datos para el mail.
const persistOut = $input.all();
let armar = [];
try { armar = $('Armar fila Control BL').all(); } catch (e) { armar = []; }

const out = [];
for (let i = 0; i < persistOut.length; i++) {
  const j = (persistOut[i] && persistOut[i].json) || {};
  if (j.id) continue;   // persistió OK
  const r = (armar[i] && armar[i].json) || (armar[0] && armar[0].json) || {};
  out.push({ json: {
    alert_order:   r.order_number || '(orden desconocida)',
    alert_booking: r.booking_no   || '',
    alert_bl:      r.bl_number     || '',
    alert_vessel:  r.vessel        || '',
    alert_when:    new Date().toISOString(),
  }});
}
return out;

/**
 * NODO Code — "Armar fila Mailing" (Mailing T1c)
 * Modo: Run Once for Each Item · JavaScript · onError: continueRegularOutput
 * Rama hermana ADITIVA desde "code  - plantilla HTML".main[0] (par de "Armar fila
 * Control BL") — nunca bloquea el mail de control ni la persistencia existente.
 *
 * Emite UN objeto = payload del upsert PostgREST a mailing_orders
 * (POST ?on_conflict=order_number + Prefer: resolution=merge-duplicates).
 * IDEMPOTENCIA: acá van SOLO las columnas que el control posee. status / sent_* /
 * schedule_override / created_at NUNCA se incluyen ⇒ re-run del control actualiza
 * datos sin pisar estado de envío ni decisiones humanas (patrón `disponible` del
 * workflow Schedule Excel).
 *
 * ship_to = consignee del parser Booking (decisión STOP 1a: el rótulo del BA es el
 * bloque combinado "Ship-to / Consignee"; reuso battle-tested, evita drift de keys).
 * Claves de directorio: normKey() — contrato único con el workflow de envío
 * (README migrations/2026-07-05-mailing-mvp).
 * PLANCOMPLETO A/B (§5.3): suma notify_key/notify_name — tercera dimensión de
 * la clave del directorio (migración 2026-07-14-plancompleto-a-notify-contactos).
 */
const COMP = 'COMPARADOR - BL vs Aduana vs Booking';
let c;
try { c = $(COMP).item.json; }
catch (e) { c = $(COMP).first().json; }
c = c || {};

const bl = c.login_extract || {};
const ba = c.booking_extract || {};
const fc = c.factura_extract || {};
const cs = c.compare_summary || {};
const kf = cs.key_fields || {};
const hr = c.header_resumen || {};

const pick = (...xs) => {
  for (const x of xs) { if (x !== undefined && x !== null && String(x).trim() !== '') return x; }
  return null;
};

// ---- normalización de claves de directorio (contrato compartido con T2) ----
const normKey = (s) => String(s || '')
  .toUpperCase()
  .normalize('NFKD').replace(/[̀-ͯ]/g, '')
  .replace(/[^A-Z0-9 ]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// ---- emails: formato válido + lowercase + dedup + filtro defensivo EXPOARPBB ----
// (la regla 18c del prompt ya lo excluye; esto es belt & suspenders determinístico)
const OWN_MAILBOX = 'expoarpbb@ssbint.com';
const cleanEmails = (arr) => {
  const seen = new Set(); const out = [];
  for (const e of (arr || [])) {
    const v = String(e || '').trim().toLowerCase();
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v)) continue;
    if (v === OWN_MAILBOX) continue;
    if (!seen.has(v)) { seen.add(v); out.push(v); }
  }
  return out;
};
const cleanOne = (e) => cleanEmails([e])[0] || null;

const order_number = pick(
  c.order_number, (kf.order_number || {}).BL, (kf.order_number || {}).Aduana,
  (kf.order_number || {}).BA, c.joinKey, bl.order_number, ba.order_number
);

// Sin orden no hay PK ⇒ el POST fallará con 400 y el HTTP (onError continue) lo
// deja pasar — mismo modo de fallo best-effort que la persistencia del Control BL.
if (!order_number) {
  console.log('[Armar fila Mailing] sin order_number — el asiento no aplica a este item');
}

const consignee = ba.consignee || {};
const sold = ba.sold_to || {};
const docR = ba.document_recip || {};
const shipR = ba.shipping_recip || {};
const notify = ba.notify || {};

const row = {
  order_number: order_number != null ? String(order_number) : null,
  booking_no: pick((kf.booking_no || {}).BL, (kf.booking_no || {}).BA, c.booking_no, bl.booking_no, ba.booking_no, hr.booking),
  bl_number: pick(kf.bl_number, bl.bl_no),
  carrier: pick(bl.carrier, c.carrier_name, c.carrier_code),
  vessel: pick(bl.vessel, hr.vessel),
  voyage: pick(bl.voyage),
  pol: pick((kf.pol || {}).BL, bl.pol, ba.pol),
  pod: pick((kf.pod || {}).BL, bl.pod, ba.pod),
  ship_to_key: normKey(consignee.name) || null,
  sold_to_key: normKey(sold.name) || '',
  // §5.3 (plancompleto A/B): el notify de la orden — tercera dimensión de la
  // clave del directorio de contactos ('' = sin notify especial → comodín).
  notify_key: normKey((notify && notify.name) || ''),
  notify_name: pick(notify.name),
  ship_to_name: pick(consignee.name),
  sold_to_name: pick(sold.name),
  invoice_no: pick(fc.invoice_no),
  contacts_extracted: {
    consignee: { name: pick(consignee.name), tax_id: pick(consignee.tax_id) },
    sold_to: { name: pick(sold.name) },
    notify: { name: pick(notify.name), email: cleanOne(notify.email) },
    document_recip: { name: pick(docR.name), email: cleanOne(docR.email) },
    shipping_recip: { name: pick(shipR.name), email: cleanOne(shipR.email) },
    partner_emails: cleanEmails(ba.partner_emails),
    source_ba_link: pick(ba.links && ba.links.webViewLink),
    extracted_at: new Date().toISOString(),
  },
  updated_at: new Date().toISOString(),
};

return { json: row };

// M3: el BL entró pero NINGUNA rama lo puede procesar — armar el aviso.
const j = $json || {};
const orden = j.order_number || '(sin orden en el nombre)';
const naviera = j.carrier_name || j.carrier_code || 'desconocida';
const motivo = j.order_match === false
  ? 'el número de orden del nombre del archivo no aparece en el texto del PDF (¿archivo mal nombrado o layout no soportado?)'
  : `la naviera detectada (${naviera}) no tiene rama de extracción en el workflow`;
const subject = `⚠️ BL NO PROCESADO — orden ${orden} (${naviera})`;
const html = `<div style=\"font-family:Arial,sans-serif;color:#222;max-width:640px;\">`
  + `<p><b>El control automático NO pudo procesar este BL.</b></p>`
  + `<table style=\"border-collapse:collapse;font-size:13px;\">`
  + `<tr><td style=\"padding:4px 10px 4px 0;color:#666;\">Archivo</td><td><b>${(j.name||'—')}</b></td></tr>`
  + `<tr><td style=\"padding:4px 10px 4px 0;color:#666;\">Orden</td><td><b>${orden}</b></td></tr>`
  + `<tr><td style=\"padding:4px 10px 4px 0;color:#666;\">Naviera detectada</td><td><b>${naviera}</b></td></tr>`
  + `<tr><td style=\"padding:4px 10px 4px 0;color:#666;\">Booking</td><td>${j.booking_no||'—'}</td></tr>`
  + `</table>`
  + `<p style=\"background:#FBEEDB;border:1px solid #ECC79A;padding:8px 12px;font-size:13px;color:#7a3300;\">Motivo: ${motivo}.</p>`
  + `<p style=\"font-size:13px;\">Qué hacer: verificar el nombre del archivo y el PDF; si la naviera es nueva o el layout cambió, avisar a John — el control de esta orden queda MANUAL hasta entonces. Este aviso reemplaza al silencio de antes (el flujo terminaba en éxito sin procesar nada).</p>`
  + `</div>`;
return { json: { alert_subject: subject, alert_html: html } };
